INSERT OR IGNORE INTO chapter (id,tier,chapter_no,title,description,`order`,status,createdAt,updatedAt) VALUES ('19-education-product',2,19,'EDUCATION & PRODUCT','Giao duc va san pham',19,'draft','2026-06-20T15:16:00Z','2026-06-20T15:16:00Z');
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('2ae95fc1-958f-42c6-88c3-005870a34fdc','19-education-product',NULL,2,'19.1 Bản đồ cấu trúc 5 trụ cột của Education / Product layer','191-ban-o-cau-truc-5-tru-cot-cua-education-product-layer',0,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('3629da00-f15b-4b84-8b64-713f4daab3f2','2ae95fc1-958f-42c6-88c3-005870a34fdc',0,'text','Một trong những rào cản lớn nhất của mô hình nha khoa truyền thống là **Tính giới hạn tuyến tính**. Doanh thu của phòng khám bị trói chặt vào số lượng ghế nha, thời gian làm việc của Bác sĩ và diện tích mặt bằng vật lý. Khi phòng khám đạt tối đa công suất ghế, tăng trưởng sẽ lập tức chạm trần.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('bff3976a-ef19-4483-b0c0-bb873ebf6945','2ae95fc1-958f-42c6-88c3-005870a34fdc',1,'text','Trong hệ điều hành **Dental Empire OS**, **Education / Product Layer (Tầng Giáo dục và Sản phẩm hóa)** được kiến tạo để phá vỡ hoàn toàn giới hạn đó.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('c2f15c9d-9ed5-4045-a817-feb3438b8064','2ae95fc1-958f-42c6-88c3-005870a34fdc',2,'text','Chúng tôi không nhìn nhận chuyên môn của Bác sĩ, kinh nghiệm lâm sàng của đội ngũ hay niềm tin của bệnh nhân như những giá trị vô hình, chỉ sử dụng một lần tại ghế điều trị. Tại phân hệ này, toàn bộ tài nguyên chất xám đó sẽ được **đóng gói, số hóa và sản phẩm hóa** thành các dạng giá trị có khả năng tái sử dụng, phân phối rộng rãi và mở rộng không giới hạn trên thị trường.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('519958eb-6a26-4903-9f0c-4e3ced753969','2ae95fc1-958f-42c6-88c3-005870a34fdc',3,'image',NULL,'book/19-education-product/3be61502-7ae9-405b-8eb3-8eddc47ffdf5-img01.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('ae56074a-6441-42d1-bfbd-25f24ebfc154','2ae95fc1-958f-42c6-88c3-005870a34fdc',4,'text','Nói một cách ngắn gọn, đây là tầng chiến lược dịch chuyển phòng khám RHM từ một nơi thuần túy "điều trị bệnh lý răng" trở thành một **Hệ sinh thái giáo dục, chăm sóc và đồng hành sức khỏe răng miệng toàn diện** cho khách hàng.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('7bc18b96-6de8-4d98-a6f6-13a2372e85fe','2ae95fc1-958f-42c6-88c3-005870a34fdc',5,'text','Để vận hành tầng này một cách thực chiến, phòng khám **Thích Làm Răng** cần triển khai đồng bộ 5 cấu phần sản phẩm cốt lõi:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('3f9f071f-7ac0-4f46-9e91-42733090745c','19-education-product','2ae95fc1-958f-42c6-88c3-005870a34fdc',3,'Trụ cột Membership (Hệ thống Hội viên trả trước)','tru-cot-membership-he-thong-hoi-vien-tra-truoc',1,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('32acf815-b44a-42a6-a8a7-971bf78eeebb','3f9f071f-7ac0-4f46-9e91-42733090745c',6,'text','- **Định nghĩa:** Chuyển đổi mô hình thu phí theo ca điều trị đơn lẻ sang mô hình thẻ thành viên đăng ký theo năm (Subscription) dành cho cá nhân hoặc hộ gia đình.- **Giá trị đóng gói:** Thẻ hội viên bảo dưỡng nụ cười, cung cấp các đặc quyền tầm soát công nghệ cao miễn phí hằng năm và giảm giá cố định cho các dịch vụ can thiệp sâu.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('ab8c555b-774d-4a37-803f-e94975cfd085','19-education-product','2ae95fc1-958f-42c6-88c3-005870a34fdc',3,'Trụ cột Sản phẩm (Homecare Product Line)','tru-cot-san-pham-homecare-product-line',2,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('65bcfdbf-3202-4ee2-9cfa-9e7357c18181','ab8c555b-774d-4a37-803f-e94975cfd085',7,'text','- **Định nghĩa:** Thương mại hóa các giải pháp chăm sóc răng miệng tại nhà có sự bảo chứng chuyên môn trực tiếp từ Bác sĩ điều trị.- **Giá trị đóng gói:** Phân phối các dòng máy tăm nước, bàn chải điện sóng siêu âm, kem đánh răng sinh học, nước súc miệng chuyên dụng mang nhãn hiệu độc quyền của phòng khám.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('2346a261-00a3-4441-a899-37047e8d2dbe','19-education-product','2ae95fc1-958f-42c6-88c3-005870a34fdc',3,'Trụ cột Workshop (Hội thảo tri thức thực địa)','tru-cot-workshop-hoi-thao-tri-thuc-thuc-ia',3,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('88ba7ee0-53f9-402f-81fa-4603e956e9e3','2346a261-00a3-4441-a899-37047e8d2dbe',8,'text','- **Định nghĩa:** Tổ chức các sự kiện giáo dục sức khỏe trực tiếp hoặc trực tuyến hướng tới từng tệp khách hàng mục tiêu chuyên biệt.- **Giá trị đóng gói:** Các buổi chia sẻ kỹ thuật (Ví dụ: Workshop chăm sóc răng sữa cho con, Talkshow kiểm soát lão hóa tầng mặt dưới), biến sảnh chờ nha khoa thành không gian giao lưu và thu hút lead tự nhiên.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('7d12b0e3-b2c7-4e30-a17d-b0f58467327c','19-education-product','2ae95fc1-958f-42c6-88c3-005870a34fdc',3,'Trụ cột Tài liệu (Digital Assets &amp; Cẩm nang số)','tru-cot-tai-lieu-digital-assets-amp-cam-nang-so',4,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('182bea10-92b7-4a2a-b153-2e91001d14a3','7d12b0e3-b2c7-4e30-a17d-b0f58467327c',9,'text','- **Định nghĩa:** Số hóa tri thức y khoa thành các tài sản nội dung có thể tải về, dễ đọc, dễ hiểu và có tính lan truyền cao.- **Giá trị đóng gói:** E-book hướng dẫn ăn uống cho người niềng răng, cẩm nang bỏ túi về cách bảo tồn tuổi thọ răng sứ, checklist hằng ngày chống viêm nha chu.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('7cebdeb9-9826-4d28-a7f4-4122de237199','19-education-product','2ae95fc1-958f-42c6-88c3-005870a34fdc',3,'Trụ cột Đào tạo (Clinical &amp; Operational Training)','tru-cot-ao-tao-clinical-amp-operational-training',5,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('6ea3b9ff-939a-485a-9b11-5b8e17b77158','7cebdeb9-9826-4d28-a7f4-4122de237199',10,'text','- **Định nghĩa:** Đóng gói quy trình vận hành và kỹ thuật lâm sàng của hệ thống để chuyển giao hoặc đào tạo thế hệ kế cận.- **Giá trị đóng gói:** Các khóa học đào tạo Trợ thủ chuyên nghiệp, chương trình chuyển giao SOP tiếp đón của Lễ tân, hoặc các khóa học kỹ thuật nha khoa chuyên sâu cho nha sĩ tuyến dưới.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('275463be-b48e-446f-9b7d-b5e4acf4c9b3','19-education-product',NULL,2,'19.2 Vai trò chiến lược toàn diện trên trục Growth Engine','192-vai-tro-chien-luoc-toan-dien-tren-truc-growth-engine',6,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('1009eebf-4f0e-4f2f-a15c-63732903d468','275463be-b48e-446f-9b7d-b5e4acf4c9b3',11,'image',NULL,'book/19-education-product/2a33d11b-d896-4b3f-ac6e-ce3697886556-img02.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('083e3227-24ea-4765-ae9b-efd6b469e46a','19-education-product','275463be-b48e-446f-9b7d-b5e4acf4c9b3',3,'Tăng độ tin tưởng trước khi mua dịch vụ (Pre-purchase Trust):','tang-o-tin-tuong-truoc-khi-mua-dich-vu-pre-purchase-trust',7,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('21cfdc72-5e38-4560-9a13-a09629631eb1','083e3227-24ea-4765-ae9b-efd6b469e46a',12,'text','Đối với các dịch vụ giá trị cao như Implant hay Răng sứ Thẩm mỹ, khách hàng thường trải qua giai đoạn do dự rất dài. Việc phân phối các tài liệu, cẩm nang số và video giáo dục từ trước giúp bẻ gãy mọi sự hoài nghi của lead lạnh trước khi họ bước chân vào phòng khám.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('0ec381ea-78cb-498e-a085-afaa59bc16ed','19-education-product','275463be-b48e-446f-9b7d-b5e4acf4c9b3',3,'Biến kiến thức chuyên môn thành tài sản nội dung:','bien-kien-thuc-chuyen-mon-thanh-tai-san-noi-dung',8,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('623add7b-b015-4bf6-9248-554bc4766c08','0ec381ea-78cb-498e-a085-afaa59bc16ed',13,'text','Thay vì Bác sĩ phải nói đi nói lại một lời dặn hậu phẫu cho 100 bệnh nhân, toàn bộ kiến thức đó được đóng gói thành một kho tài nguyên nội dung chuẩn hóa, chuyên nghiệp và có thể phân phối tự động qua CRM.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('3aaf6242-e621-46e1-bee0-8100e1854db9','19-education-product','275463be-b48e-446f-9b7d-b5e4acf4c9b3',3,'Tạo sản phẩm phụ trợ ngoài dịch vụ điều trị:','tao-san-pham-phu-tro-ngoai-dich-vu-ieu-tri',9,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('48efd2fa-b90a-4b3a-8d99-29bc6d97cd6a','3aaf6242-e621-46e1-bee0-8100e1854db9',14,'text','Giúp phòng khám duy trì dòng tiền mặt đều đặn ngay cả khi khách hàng không phát sinh nhu cầu làm răng. Việc bán một chiếc máy tăm nước hay một set quà Homecare giữ cho thương hiệu luôn xuất hiện trong nhà tắm của khách hàng mỗi ngày 2 lần.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('a117b5f5-80c1-42e4-8d37-a4cdee372ca0','19-education-product',NULL,2,'19.3 Phân hệ Membership','193-phan-he-membership',10,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('37c81754-b138-4e5d-9742-3a304a1a56ea','a117b5f5-80c1-42e4-8d37-a4cdee372ca0',15,'text','**Kiến tạo hệ thống thành viên và cam kết chăm sóc dài hạn**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('c3e92274-7399-401f-bff9-c416c49374e1','a117b5f5-80c1-42e4-8d37-a4cdee372ca0',16,'text','Trong kiến trúc tổng thể của **Education / Product Layer**, phân hệ **Membership (Chương trình thành viên)** đóng vai trò là vũ khí tối thượng để bẻ gãy mô hình kinh doanh "chờ bệnh nhân đau mới đến khám". Đây là hệ thống số hóa cam kết chăm sóc sức khỏe răng miệng dài hạn giữa phòng khám RHM và bệnh nhân.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('bffb95a3-51cc-48ca-a94d-4d352e8f02a7','a117b5f5-80c1-42e4-8d37-a4cdee372ca0',17,'text','Một chương trình Membership chuẩn mực trong hệ điều hành **Dental Empire OS** tuyệt đối không phải là một chiếc thẻ giảm giá (Discount Card) thông thường. Nếu bạn chỉ dùng chiêu trò giảm giá để lôi kéo, bạn đang tự hạ thấp giá trị chuyên môn của *Clinic System* và thu hút tệp khách hàng ham rẻ, thiếu trung thành.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('5d3db721-d11e-4d20-a477-0801931fe2a2','a117b5f5-80c1-42e4-8d37-a4cdee372ca0',18,'text','Bản chất của Membership là **Đóng gói một cam kết về kết quả sức khỏe (Outcome-based Commitment)**, mang lại giá trị thực chứng giúp bệnh nhân chủ động bảo vệ nụ cười của mình, đồng thời tạo ra dòng tiền mặt trả trước (Upfront Cashflow) bền vững cho doanh nghiệp.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('b708ad84-0fbb-4b41-ba98-6b2a957d16d4','19-education-product','a117b5f5-80c1-42e4-8d37-a4cdee372ca0',3,'Bốn mục tiêu chiến lược của hệ thống thành viên','bon-muc-tieu-chien-luoc-cua-he-thong-thanh-vien',11,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('b468e4c6-7a27-4e2e-b777-7c36d7014f01','b708ad84-0fbb-4b41-ba98-6b2a957d16d4',19,'image',NULL,'book/19-education-product/63118380-d963-44aa-bb7b-706ffc87b6dc-img03.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('6f978fed-e1b5-4327-af05-016c89de5a19','b708ad84-0fbb-4b41-ba98-6b2a957d16d4',20,'text','Khi triển khai phân hệ Membership trên hệ thống CRM, phòng khám hướng tới 4 mục tiêu chuyển đổi hành vi cốt lõi:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('92659262-1b32-4d07-b879-268efc8b0ada','b708ad84-0fbb-4b41-ba98-6b2a957d16d4',21,'text','- **Tăng tỷ lệ giữ chân (Maximize Retention Rate):** Thiết lập một rào cản lợi ích và cảm xúc khép kín, khiến chi phí chuyển đổi (Switching Cost) sang phòng khám đối thủ của bệnh nhân trở nên quá cao.- **Tăng tỷ lệ tái khám chủ động (Boost Recall Rate):** Tạo thói quen chăm sóc răng miệng định kỳ cho khách hàng thông qua chuỗi lịch hẹn được lập trình sẵn theo chu kỳ sinh học y khoa.- **Kéo giãn Giá trị vòng đời bệnh nhân (Patient Lifetime Value - LTV):** Chuyển hóa một hồ sơ khách hàng từ trạng thái giao dịch một lần thành một dòng tiền đóng góp đều đặn vào doanh thu phòng khám trong 3 năm, 5 năm hoặc trọn đời.- **Tạo dòng khách Referral chất lượng cao:** Biến nhóm hội viên VIP thành cái phễu lọc truyền miệng, kích hoạt phản xạ giới thiệu người thân thông qua các đặc quyền gia đình.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('3311d35e-1158-4c6b-a1ff-13fd53be0ca9','19-education-product','a117b5f5-80c1-42e4-8d37-a4cdee372ca0',3,'Ma trận 5 dạng membership nha khoa thực chiến','ma-tran-5-dang-membership-nha-khoa-thuc-chien',12,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('b1f93e7f-2609-4a14-bcd7-177a76c2c947','3311d35e-1158-4c6b-a1ff-13fd53be0ca9',22,'text','Tùy thuộc vào năng lực vận hành và tệp dữ liệu khách hàng, phòng khám **Thích Làm Răng** có thể linh hoạt cấu hình 5 dạng chương trình thành viên dưới đây:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('b6603d11-e403-4877-b0b9-0a8e351302e9','19-education-product','3311d35e-1158-4c6b-a1ff-13fd53be0ca9',4,'Membership Chăm sóc định kỳ (Periodic Care Package)','membership-cham-soc-inh-ky-periodic-care-package',13,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('eb8376bc-6da2-443d-bb3a-f19a329d1b70','b6603d11-e403-4877-b0b9-0a8e351302e9',23,'text','- **Bản chất:** Gói dịch vụ chăm sóc và tầm soát nha khoa cơ bản theo chu kỳ năm.- **Quyền lợi cốt lõi:** Khám răng tổng quát và cạo vôi răng định kỳ 6 tháng/lần; sử dụng công nghệ quét dấu hàm 3D tầm soát sớm; hệ thống tự động nhắc lịch hẹn; xuất báo cáo tình trạng sức khỏe răng miệng cá nhân hóa gửi qua Zalo OA hậu điều trị.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('c1c63621-a55e-4379-83a0-14d86ca4544c','19-education-product','3311d35e-1158-4c6b-a1ff-13fd53be0ca9',4,'Membership Bảo trì sau điều trị (Post-treatment Maintenance)','membership-bao-tri-sau-ieu-tri-post-treatment-maintenance',14,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('00c3cf4e-db0f-4049-948f-a1737e971443','c1c63621-a55e-4379-83a0-14d86ca4544c',24,'text','- **Bản chất:** Gói bảo dưỡng bắt buộc dành riêng cho các ca can thiệp lâm sàng lớn (Implant, Chỉnh nha, Răng sứ Thẩm mỹ).- **Quyền lợi cốt lõi:** Tập trung nghiêm ngặt vào các tác vụ Recall lâm sàng. Ví dụ: Chụp phim X-quang kiểm tra độ khít sát nướu định kỳ cho răng sứ; kiểm tra tốc độ tích hợp xương và vệ sinh chuyên dụng bằng máy tăm nước sóng siêu âm cho răng Implant.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('08cb6ca1-0d46-4eb3-8fe1-b46c42034e11','19-education-product','3311d35e-1158-4c6b-a1ff-13fd53be0ca9',4,'Membership Gia đình (Family Healthcare Pass)','membership-gia-inh-family-healthcare-pass',15,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('d329e6bd-5bce-4044-b7dc-da0066f2a35e','08cb6ca1-0d46-4eb3-8fe1-b46c42034e11',25,'text','- **Bản chất:** Một tài khoản hội viên, bảo bọc sức khỏe răng miệng cho cả tổ ấm.- **Quyền lợi cốt lõi:** Đồng bộ hóa lịch tái khám cho cả nhà trong cùng một ngày hẹn để tiết kiệm thời gian di chuyển; chính sách chia sẻ hạn mức ưu đãi đặc quyền cho người thân; cung cấp kho nội dung giáo dục thường thức riêng biệt cho phụ huynh về cách chăm sóc răng trẻ em.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('cb42b125-3214-410d-ab4c-b454d8a020ff','19-education-product','3311d35e-1158-4c6b-a1ff-13fd53be0ca9',4,'Membership Theo dịch vụ chủ lực (Service-specific Tier)','membership-theo-dich-vu-chu-luc-service-specific-tier',16,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('ff3cc0e2-7613-483e-8def-57acf5261cd8','cb42b125-3214-410d-ab4c-b454d8a020ff',26,'text','- **Bản chất:** Phân tầng thẻ thành viên sâu dựa trên nhu cầu điều trị mũi nhọn của phòng khám (Tệp Niềng răng, Tệp Nha chu, Tệp Răng trẻ em, Tệp Thẩm mỹ).- **Quyền lợi cốt lõi:** Mỗi nhóm dịch vụ sẽ được cấu hình một bộ Checklist theo dõi, lịch trình Recall lâm sàng và kho tài liệu hướng dẫn (Digital Guides) hoàn toàn biệt lập, đúng ngữ cảnh tâm lý.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('cd2887d3-1bd0-4d50-8278-6441989f9f17','19-education-product','3311d35e-1158-4c6b-a1ff-13fd53be0ca9',4,'Membership Cộng đồng (Tribe Community Pass)','membership-cong-ong-tribe-community-pass',17,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('eccbd18d-bd2f-4aaa-b3f1-f7a55ab6fd00','cd2887d3-1bd0-4d50-8278-6441989f9f17',27,'text','- **Bản chất:** Mô hình hội viên kết hợp phong cách sống và giao lưu tri thức cao cấp.- **Quyền lợi cốt lõi:** Kích hoạt tài khoản tham gia vào các tiểu cộng đồng kín; mở khóa đặc quyền tham dự các buổi Workshop Offline, các buổi Livestream Q&A trực tiếp cùng Bác sĩ sáng lập; nhận bộ quà tặng phi y khoa vào các dịp lễ lớn.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('fe4b2690-d992-4376-b275-4c08d23dc7f2','19-education-product','a117b5f5-80c1-42e4-8d37-a4cdee372ca0',3,'Chiến lược lựa chọn gói membership theo giai đoạn phòng khám','chien-luoc-lua-chon-goi-membership-theo-giai-oan-phong-kham',18,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('7fef870d-8795-4d5a-91f8-d19b85ebce83','fe4b2690-d992-4376-b275-4c08d23dc7f2',28,'text','Để hệ thống không bị quá tải vận hành, Nhà quản trị bắt buộc phải lựa chọn dạng Membership phù hợp với độ trưởng thành của phòng khám:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('09176602-f1ba-4ea9-acc0-be60f4e6437c','fe4b2690-d992-4376-b275-4c08d23dc7f2',29,'image',NULL,'book/19-education-product/11879082-1fc0-41ba-be74-3c2140e70034-img04.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('a589e908-0d42-4877-89bc-5a2bfd376a0d','19-education-product','fe4b2690-d992-4376-b275-4c08d23dc7f2',4,'Cấu trúc bắt buộc của một gói membership tiêu chuẩn','cau-truc-bat-buoc-cua-mot-goi-membership-tieu-chuan',19,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('0e6057f0-655c-4fe2-9034-cce56722a3ef','a589e908-0d42-4877-89bc-5a2bfd376a0d',30,'text','Một chương trình thành viên muốn vận hành ra tiền thực tế, không bị rơi vào trạng thái "chết lâm sàng" trên hệ thống, bắt buộc phải được cấu thành từ 4 cấu phần lõi sau:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('ab2e64b2-5674-43fb-aeff-23843f39af63','a589e908-0d42-4877-89bc-5a2bfd376a0d',31,'text','- **Quyền lợi rõ ràng (Transparent Benefits):** Hiển thị minh bạch các dịch vụ được miễn phí 100% và các dịch vụ được ưu đãi đặc quyền. Tuyệt đối không mập mờ chi phí ẩn khiến khách hàng nghi ngờ.- **Lịch chăm sóc định kỳ (Scheduled Routine Care):** Gắn liền gói hội viên với một lịch trình thời gian cụ thể (Ví dụ: Tháng 6 tầm soát khớp cắn, Tháng 12 cạo vôi răng bảo tồn).- **Ưu đãi người thân (Family Referral Alignment):** Thiết lập một điều khoản cho phép hội viên chính thức "tặng" đặc quyền khám miễn phí cho 1-2 người thân. Đây chính là ngòi nổ kích hoạt dòng khách Referral dồi dào.- **Đường ống tự động hóa (Automated Follow-up Engine):** Toàn bộ quy trình từ nhắc lịch hẹn, gửi nội dung giáo dục thường thức trước ngày khám cho đến gửi lời chúc mừng sinh nhật phải được lập trình chạy tự động 100% qua hệ thống CRM của *Patient OS*.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('b70491c2-fa1e-4bc6-94bb-d3ab8bffe6df','19-education-product','fe4b2690-d992-4376-b275-4c08d23dc7f2',4,'Lộ trình 5 bước triển khai nhanh Membership (quick deployment blueprint)','lo-trinh-5-buoc-trien-khai-nhanh-membership-quick-deployment-blueprint',20,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('4e809ca9-b9c8-4e2d-8c82-be97ac8c386b','b70491c2-fa1e-4bc6-94bb-d3ab8bffe6df',32,'image',NULL,'book/19-education-product/145452ea-d379-4d7c-813c-ee3d06490589-img05.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('3678fd02-3b8c-4f27-820f-be996c8b5ca5','b70491c2-fa1e-4bc6-94bb-d3ab8bffe6df',33,'text','Để biến ý tưởng Membership thành quy trình vận hành thực địa trong vòng 30 ngày, Nhà quản trị thực thi theo đúng lộ trình tuyến tính sau:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('2a11d6f0-7124-479d-8b9c-36eada3e485e','b70491c2-fa1e-4bc6-94bb-d3ab8bffe6df',34,'text','- **Bước 1:** Lựa chọn duy nhất **1 dịch vụ chủ lực** của phòng khám (Ví dụ: dịch vụ Chỉnh nha hoặc dịch vụ Răng sứ Thẩm mỹ) làm bàn đạp thử nghiệm.- **Bước 2:** Thiết kế **1 gói Membership Core** độc quyền hướng tới việc giải quyết nỗi đau lớn nhất của tệp khách dịch vụ chủ lực đó (Ví dụ: Gói bảo trì chống chạy răng sau tháo niềng).- **Bước 3:** Cấu hình mở rộng thêm **1 gói Family Pass** phụ trợ để quét thêm tệp người thân đi cùng.- **Bước 4:** Biên soạn và đóng gói hoàn thiện **1 bộ tài liệu giáo dục** đi kèm (E-book/Checklist) kết hợp lập trình **1 luồng Recall Flow tự động** trên CRM.- **Bước 5:** Tiến hành chạy thử nghiệm nội bộ, đo lường các chỉ số tương tác trước khi mở rộng quy mô sang hệ thống Workshop và xây dựng Tiểu cộng đồng (Micro-Community) diện rộng.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('d144d1b2-ad60-4a51-b3cf-2105e2af1b24','19-education-product','fe4b2690-d992-4376-b275-4c08d23dc7f2',4,'Bảng Membership mẫu','bang-membership-mau',21,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('5d324785-4cf7-4ecd-9cbc-b54fbc5162bd','d144d1b2-ad60-4a51-b3cf-2105e2af1b24',35,'image',NULL,'book/19-education-product/7e2890ce-10ab-4135-a213-59146dfe8cd1-img06.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('2c846af3-03ad-4743-9a02-e544d70c2d20','19-education-product','fe4b2690-d992-4376-b275-4c08d23dc7f2',4,'Bộ chỉ số KPI cốt lõi đo lường hiệu suất vận hành Membership','bo-chi-so-kpi-cot-loi-o-luong-hieu-suat-van-hanh-membership',22,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('fc8631dd-1042-4e1c-92ab-384157c18dbc','2c846af3-03ad-4743-9a02-e544d70c2d20',36,'text','Để đảm bảo phân hệ **Membership** hoạt động như một thực thể sinh lời thực tế chứ không phải một danh mục bổ sung danh nghĩa, Nhà quản trị của hệ điều hành **Dental Empire OS** phải theo dõi nghiêm ngặt bộ chỉ số hiệu suất trên Dashboard hằng tuần.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('5f885732-9b90-4519-bad0-d873bf7b098c','2c846af3-03ad-4743-9a02-e544d70c2d20',37,'text','Một chương trình thành viên chỉ thực sự hiệu quả khi nó giải quyết được đồng thời ba bài toán hành vi: **Khiến bệnh nhân quay lại đúng hẹn, khiến họ cảm thấy được bao bọc an toàn và cung cấp cho họ một lý do đủ lớn để giới thiệu người thân.**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('e9fba3dc-9435-43b8-b390-03f510539ffc','2c846af3-03ad-4743-9a02-e544d70c2d20',38,'text','Để làm được điều đó, Dashboard của phòng khám bắt buộc phải cấu hình 6 chỉ số KPI tối thiểu sau:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('c3a96620-d0c7-4d0f-95cf-a897cfe64131','2c846af3-03ad-4743-9a02-e544d70c2d20',39,'image',NULL,'book/19-education-product/2815891e-866e-41a0-a2c9-54bb2bb50c43-img07.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('cc016b56-1990-4786-ae46-084630d3df8f','2c846af3-03ad-4743-9a02-e544d70c2d20',40,'text','**Mối liên kết hệ thống (Cross-OS Alignment):** Theo đúng logic của **Dental Empire OS**, phân hệ Membership không được đứng cô lập trên báo cáo tài chính. Nó phải được kết nối trực tiếp với Dashboard của **Patient OS** (để theo dõi xem gói nào tạo tỷ lệ giữ chân - Retention tốt nhất) và **Referral OS** (để định vị xem phân khúc hội viên nào đang mang lại hiệu quả truyền miệng cao nhất). Nếu tỷ lệ sử dụng quyền lợi (*Benefit Utilization Rate*) sụt giảm, đó là tín hiệu cảnh báo đường ống nhắc lịch tự động của Patient OS đang bị gãy điểm chạm.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('16e0e549-5df0-4f9b-ad9c-742181b2410c','19-education-product','fe4b2690-d992-4376-b275-4c08d23dc7f2',4,'Nghệ thuật bán membership thực chiến: chốt bằng điểm đau, không bán giảm giá','nghe-thuat-ban-membership-thuc-chien-chot-bang-iem-au-khong-ban-giam-gia',23,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('13b79a2f-e90c-4135-9bc2-7ac9e64db318','16e0e549-5df0-4f9b-ad9c-742181b2410c',41,'text','Sai lầm lớn nhất của đội ngũ Lễ tân và CSKH khi tư vấn chương trình thành viên là cố gắng chèo kéo khách hàng bằng các cụm từ: *"Anh chị mua gói này đi để được giảm giá nhiều hơn"*. Lối tư vấn này vô tình hạ thấp vị thế tử tế của phòng khám, biến một chương trình chăm sóc y khoa cao cấp thành một "combo giảm giá" rẻ tiền của ngành bán lẻ thương mại.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('f8695bb8-6c47-4667-8f02-99ff1dbb7d27','16e0e549-5df0-4f9b-ad9c-742181b2410c',42,'text','**Nguyên tắc tối thượng của Dental Empire OS: ***Bán Membership là bán một giải pháp chăm sóc dài hạn với quyền lợi rõ ràng, thời hạn rõ ràng và kết quả mong đợi (Outcome) rõ ràng.*',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('eaa7da9c-8d5c-402e-bda4-bfa7faa55f34','16e0e549-5df0-4f9b-ad9c-742181b2410c',43,'text','Để tỷ lệ chốt đạt mức tối ưu, đội ngũ tư vấn bắt buộc phải gắn gói Membership vào đúng **4 Điểm đau thực tế (Real Pain Points)** của bệnh nhân:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('22159935-647d-4dbc-abec-64747b5da7e5','16e0e549-5df0-4f9b-ad9c-742181b2410c',44,'text','- **Điểm đau 1: Sự đãng trí và lười biếng hằng ngày:** Khách hàng luôn bận rộn và họ thường xuyên quên lịch tái khám định kỳ, chỉ đến khi răng đau buốt mới chịu đi nha sĩ.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('721c30ac-e5af-44c9-b470-044b36a3fd3f','16e0e549-5df0-4f9b-ad9c-742181b2410c',45,'text','➔ *Giải pháp bán:* Membership đóng vai trò như một "trợ lý sức khỏe thông minh", tự động tính toán chu kỳ sinh học và bao bọc lịch hẹn cho họ.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('dfd5fc0f-c9fc-4efe-8021-9f2996212a59','16e0e549-5df0-4f9b-ad9c-742181b2410c',46,'text','- **Điểm đau 2: Sự hoang mang hậu điều trị:** Bệnh nhân sau khi thực hiện các ca lâm sàng lớn (Niềng răng, Implant, Răng sứ) thường thiếu kiến thức và không biết cách tự chăm sóc, bảo tồn răng tại nhà.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('37edf2ca-5323-4ae1-a17c-3c27dae2e200','16e0e549-5df0-4f9b-ad9c-742181b2410c',47,'text','➔ *Giải pháp bán:* Gói hội viên cung cấp sự bảo chứng y khoa liên tục cùng Bác sĩ trưởng ca và kho tài liệu hướng dẫn độc quyền.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('6cc8a706-4482-4c3b-a6c6-591c3b192f81','16e0e549-5df0-4f9b-ad9c-742181b2410c',48,'text','- **Điểm đau 3: Nỗi sợ hãi chi phí ẩn phát sinh:** Khách hàng lo lắng về việc mỗi lần bước chân vào nha khoa là một lần phát sinh hàng loạt chi phí kiểm tra, chụp phim, tầm soát không rõ ràng.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('a55232a7-273e-4a24-b954-18d8e39086df','16e0e549-5df0-4f9b-ad9c-742181b2410c',49,'text','➔ *Giải pháp bán:* Membership khóa chặt mọi chi phí kiểm tra cơ bản về mốc 0đ trọn năm.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('556dacfb-aa0d-4817-9999-f3084781db76','16e0e549-5df0-4f9b-ad9c-742181b2410c',50,'text','- **Điểm đau 4: Khát vọng đồng bộ sức khỏe tổ ấm:** Người làm trụ cột gia đình luôn muốn bố mẹ, con cái của mình được chăm sóc răng miệng tại một nơi uy tín, đồng bộ dữ liệu bệnh án để dễ dàng theo dõi.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('0f540829-9c3c-45f4-aea1-75b020b887ae','16e0e549-5df0-4f9b-ad9c-742181b2410c',51,'text','➔ *Giải pháp bán:* Gói thẻ gia đình Family Pass giúp đồng bộ hóa lịch khám và tối ưu thời gian di chuyển cho cả nhà.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('1c55d145-0654-4885-bfe8-7f9183f1a4f4','19-education-product','fe4b2690-d992-4376-b275-4c08d23dc7f2',4,'Ba thời điểm vàng để chốt membership (the golden points of sale)','ba-thoi-iem-vang-e-chot-membership-the-golden-points-of-sale',24,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('d785a48b-14cb-4748-8d0d-4dbf66d2549d','1c55d145-0654-4885-bfe8-7f9183f1a4f4',52,'text','Nhân sự không được chào mời gói thành viên một cách ngẫu nhiên, mà phải thực hiện chuẩn xác tại 3 thời điểm có độ chín tâm lý cao nhất trên hành trình bệnh nhân:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('40fe3978-20d0-4878-aee3-b230ed1c97c1','1c55d145-0654-4885-bfe8-7f9183f1a4f4',53,'image',NULL,'book/19-education-product/65529556-6be9-4a04-80e5-0af2785152c1-img08.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('449dbffd-2b02-4ef5-b9d8-467ece329cf0','1c55d145-0654-4885-bfe8-7f9183f1a4f4',54,'text','- **Ngay sau khi khám tổng quát:** Khi Bác sĩ vừa tầm soát xong và chỉ ra các nguy cơ chớm sâu răng hoặc viêm nướu nhẹ của khách. Lễ tân sẽ chốt gói *Smile Standard* như một giải pháp phòng bệnh tiết kiệm.- **Ngay sau khi ca điều trị hoàn tất:** Đây là thời điểm bệnh nhân đạt trạng thái cảm xúc đỉnh cao (**Wow Peak**), họ đang vô cùng hạnh phúc với nụ cười mới và biết ơn Bác sĩ. Lễ tân kích hoạt gói *Premium Maintenance* để giúp họ bảo tồn thành quả thẩm mỹ đó trọn đời.- **Ngay trong buổi tư vấn phác đồ dịch vụ có vòng đời dài (Implant / Chỉnh nha):** Thay vì để khách hàng lo sợ về chi phí bảo dưỡng hậu phẫu phức tạp sau này, Chuyên viên tư vấn sẽ tặng kèm hoặc tích hợp sẵn gói Membership cao cấp vào tổng giá trị gói điều trị như một món quà cam kết đồng hành trọn đời của thương hiệu **Thích Làm Răng**.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('2c77ca7f-126b-4823-b6a0-8bf2c0af7ae1','19-education-product','fe4b2690-d992-4376-b275-4c08d23dc7f2',4,'Lộ trình kích hoạt nhanh 30 ngày (30-day deployment blueprint)Để biến toàn bộ phân hệ Membership thành một quy trình vận hành tự chạy hằng tuần trên thực địa phòng khám, Nhà quản trị áp dụng nghiêm ngặt lộ trình 5 bước sau:','lo-trinh-kich-hoat-nhanh-30-ngay-30-day-deployment-blueprinte-bien-toan-bo-phan-',25,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('50ca29c2-a09f-446e-b4e8-3e990b6aeeec','2c77ca7f-126b-4823-b6a0-8bf2c0af7ae1',55,'text','- **Bước 1 (*****Ngày 1 - 7)*****: Giới hạn danh mục sản phẩm: **Tuyệt đối không thiết kế quá nhiều gói gây nhiễu hệ thống. Chỉ lựa chọn duy nhất **1 gói cơ bản** (Chăm sóc tổng quát) và **1 gói chuyên sâu** theo dịch vụ mũi nhọn của phòng khám để tập trung nguồn lực vận hành.- **Bước 2 (*****Ngày 8 - 14)*****: Chuẩn hóa kiến trúc văn bản: **Viết rõ ràng, ngắn gọn toàn bộ quyền lợi được hưởng, điều kiện áp dụng, thời hạn sử dụng thẻ và lập trình sẵn quy trình nhắc lịch hẹn tự động (Recall Flow) tương ứng trên hệ thống CRM.- **Bước 3 (*****Ngày 15 - 21)*****: Đóng gói tài liệu & Đào tạo Script: **Sản xuất bộ ấn phẩm thẻ (Vật lý hoặc mã QR điện tử). Biên soạn tài liệu hướng dẫn mẫu (Sales Script) hướng dẫn chi tiết cho Lễ tân và bộ phận CSKH cách bóc tách điểm đau để tư vấn chốt Membership tự nhiên.- **Bước 4 (*****Ngày 22 - 28)*****: Số hóa Dashboard & Gắn KPI: **Cấu hình các trường chỉ số (Tỷ lệ mua, doanh thu trả trước, số ca giới thiệu phát sinh) lên hệ thống dữ liệu chung để ban giám đốc tiến hành giao chỉ tiêu và kiểm soát hiệu suất hằng tuần.- **Bước 5 (*****Ngày 29 - 30)*****: Đánh giá và Tối ưu hóa chu kỳ: **Sau 30 ngày vận hành thực địa, tiến hành trích xuất dữ liệu để phân tích: Đo lường chính xác tỷ lệ khách đồng ý mua, tỷ lệ hội viên thực sự đến khám và tỷ lệ gia hạn thẻ để tiến hành căn chỉnh, hoàn thiện hệ thống trước khi mở rộng quy mô sang phân hệ Workshop và xây dựng Tiểu cộng đồng (Micro-Community).',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('2b6a7bc4-0c7e-44a0-9a68-28e1ba8d4db8','19-education-product',NULL,2,'19.5 Phân hệ sản phẩm hóa (Product Line)','195-phan-he-san-pham-hoa-product-line',26,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('a201330e-df3d-4697-bc61-1b1cd3e81082','2b6a7bc4-0c7e-44a0-9a68-28e1ba8d4db8',56,'text','**Biến tri thức y khoa thành giải pháp đồng hành trong đời sống hằng ngày**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('9210bd0a-15de-455c-a64f-7fe549bd1346','2b6a7bc4-0c7e-44a0-9a68-28e1ba8d4db8',57,'text','Nếu phân hệ *Membership* là sợi dây cam kết về mặt thời gian và tài chính giữa bệnh nhân với phòng khám RHM, thì phân hệ **Sản phẩm hóa (Product Line)** trong tầng *Education / Product Layer* chính là công cụ vật chất hóa sự chăm sóc đó vào đời sống hằng ngày của khách hàng.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('71d70b83-1473-4bba-b9c7-70685acca648','2b6a7bc4-0c7e-44a0-9a68-28e1ba8d4db8',58,'text','Sai lầm chí mạng của 90% các phòng khám nha khoa hiện nay là xem việc bán kem đánh răng, nước súc miệng hay máy tăm nước như một hoạt động bán lẻ tạp hóa phụ trợ, có thì tốt, không có cũng chẳng sao. Họ bày sản phẩm trong tủ kính sảnh chờ như một món đồ trang trí, nhân viên lễ tân thì bán hàng theo kiểu "ai hỏi thì đưa". Cách làm này không những làm lãng phí một nguồn doanh thu khổng lồ mà còn tự cắt đứt một điểm chạm thương hiệu cực mạnh trong nhà tắm của khách hàng - nơi họ nhìn thấy nhãn hiệu của bạn đều đặn mỗi ngày 2 lần.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('30d1e148-c7e8-41dd-b390-543ea1218e3e','2b6a7bc4-0c7e-44a0-9a68-28e1ba8d4db8',59,'text','Trong kiến trúc **Dental Empire OS**, chúng tôi định nghĩa lại: **Sản phẩm nha khoa không phải là hàng hóa thương mại đơn thuần, mà là Phác đồ bảo tồn kết quả lâm sàng tại nhà dưới sự bảo chứng chuyên môn của Bác sĩ.**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('892df0a3-fcde-4dac-a978-8fa2f4297bb8','2b6a7bc4-0c7e-44a0-9a68-28e1ba8d4db8',60,'text','Khi bạn dịch chuyển từ tư duy "bán hàng lẻ" sang "bán giải pháp xử lý vấn đề", phòng khám của bạn sẽ chính thức mở rộng được giá trị hậu điều trị vượt ra khỏi phạm vi giới hạn của chiếc ghế nha vật lý.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('6cebf562-53e3-41a7-8929-d9eb53135cc6','19-education-product','2b6a7bc4-0c7e-44a0-9a68-28e1ba8d4db8',3,'Ba trụ cột cấu trúc danh mục sản phẩm và dịch vụ đóng gói','ba-tru-cot-cau-truc-danh-muc-san-pham-va-dich-vu-ong-goi',27,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('97f89396-2199-4290-a454-b218a2880f5e','6cebf562-53e3-41a7-8929-d9eb53135cc6',61,'text','Để tối ưu hóa trải nghiệm hậu điều trị và kích hoạt dòng tiền lặp lại, danh mục sản phẩm của hệ thống **Thích Làm Răng** được chia tách cấu trúc thành 3 nhóm chiến lược:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('0c554d59-2598-4a34-936d-a0e5bc00b32b','19-education-product','6cebf562-53e3-41a7-8929-d9eb53135cc6',4,'Nhóm 1: Sản phẩm chăm sóc răng miệng thường nhật (Daily Homecare Essentials)','nhom-1-san-pham-cham-soc-rang-mieng-thuong-nhat-daily-homecare-essentials',28,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('00935ade-d2d9-41bd-b44d-ae2f9cf4e219','0c554d59-2598-4a34-936d-a0e5bc00b32b',62,'text','Đây là nhóm sản phẩm có tần suất sử dụng cao nhất, dễ bán nhất vì nó gắn liền với nhu cầu sinh hoạt cơ bản của mọi thành viên trong gia đình bệnh nhân:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('b3cf2be9-14c3-458b-8c50-f183b9ad9145','0c554d59-2598-4a34-936d-a0e5bc00b32b',63,'text','- Kem đánh răng chuyên biệt (chống ê buốt, bảo vệ nướu, men răng sinh học).- Bàn chải điện sóng siêu âm hoặc bàn chải sợi siêu mềm theo chỉ định y khoa.- Chỉ nha khoa cao cấp, bàn chải kẽ răng chuyên sâu.- Nước súc miệng thảo mộc diệt khuẩn tầng sâu, Gel/Serum sinh học chăm sóc nướu chủ động.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('15380143-4884-495d-b871-b760c9dc3988','19-education-product','6cebf562-53e3-41a7-8929-d9eb53135cc6',4,'Nhóm 2: Sản phẩm chuyên môn hóa theo dịch vụ (Indication-Specific Kits)','nhom-2-san-pham-chuyen-mon-hoa-theo-dich-vu-indication-specific-kits',29,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('eee07520-194d-4ea4-bcc2-308459effe4c','15380143-4884-495d-b871-b760c9dc3988',64,'text','Nhóm này giúp phòng khám biến kiến thức chuyên môn khô khan thành các bộ giải pháp vật lý có biên lợi nhuận cao. Sản phẩm được đóng gói thành các "Kit" giải quyết trọn gói nỗi đau của từng nhóm bệnh lý sau điều trị:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('5dae7610-0b48-4fd6-8990-42e1f6dbcfbc','15380143-4884-495d-b871-b760c9dc3988',65,'text','- **Orthodontic Care Kit:** Bộ vệ sinh và bảo vệ toàn diện cho người niềng răng.- **Retainer Care Kit:** Bộ làm sạch và bảo quản khay duy trì sau tháo niềng.- **Implant Aftercare Kit:** Bộ giải pháp chống viêm quanh trụ và bảo vệ xương hàm.- **Gum Care Kit / Sensitive Teeth Kit:** Bộ chăm sóc nướu nha chu và răng nhạy cảm.- **Whitening Maintenance Kit:** Bộ giữ màu và bù men khoáng sau tẩy trắng răng.- **Kids / Senior / Travel Oral Care Kit:** Các bộ kit chuyên biệt theo độ tuổi và ngữ cảnh di chuyển.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('7f473b00-26fe-45f5-8ecf-a9ee3cb2daac','19-education-product','6cebf562-53e3-41a7-8929-d9eb53135cc6',4,'Nhóm 3: Gói dịch vụ chăm sóc đóng gói (Packaged Services)','nhom-3-goi-dich-vu-cham-soc-ong-goi-packaged-services',30,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('d8f70991-e00a-4972-9729-ceaa7739d2cd','7f473b00-26fe-45f5-8ecf-a9ee3cb2daac',66,'text','Sự kết hợp giữa sản phẩm vật lý và các tác vụ lâm sàng định kỳ nhằm tạo ra dòng doanh thu lặp lại ổn định (Recurring Revenue):',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('c075ed37-3ec9-46fd-bb07-79781f41ee50','7f473b00-26fe-45f5-8ecf-a9ee3cb2daac',67,'text','- Gói vệ sinh răng miệng và tầm soát túi nha chu định kỳ 6 tháng.- Gói theo dõi, chụp phim và bảo dưỡng chuyên sâu sau cấy ghép Implant theo năm.- Gói kiểm tra định kỳ và kiểm soát khớp cắn cho tệp răng sứ thẩm mỹ VIP.- Gói chăm sóc răng trẻ em theo quý (bôi Fluor chống sâu răng chủ động).',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('af2b80f1-fcf1-40b4-b30d-dcecf21a8ea5','19-education-product','2b6a7bc4-0c7e-44a0-9a68-28e1ba8d4db8',3,'Nghệ thuật đón gói "vấn đề": không bán loại hàng, hãy bán tình huống sử dụng','nghe-thuat-on-goi-van-e-khong-ban-loai-hang-hay-ban-tinh-huong-su-dung',31,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('82f44eb1-1bb6-42ad-84ed-47b2e903a782','af2b80f1-fcf1-40b4-b30d-dcecf21a8ea5',68,'text','Bệnh nhân bước vào phòng khám nha khoa không phải để mua một tuýp kem đánh răng hay một cuộn chỉ nha khoa. Thứ họ thực sự xuống tiền mua là **Sự an tâm về một kết quả điều trị bền vững**. Do đó, quy tắc đóng gói sản phẩm cốt lõi của hệ thống là: **Đóng gói theo tình huống sử dụng và vấn đề thực tế, tuyệt đối không bán rời rạc theo loại hàng.**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('8586f38c-da26-4c13-b105-ec7a0ba835ba','af2b80f1-fcf1-40b4-b30d-dcecf21a8ea5',69,'text','Thay vì bán một "bộ vệ sinh răng niềng" chung chung, hãy đóng gói và đặt tên nó là **"Kit chăm sóc răng sau niềng 30 ngày đầu"** hoặc **"Kit bảo vệ và chống đào thải Implant 6 tháng đầu"**.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('1be7bcc7-898e-4fb8-915e-5202d9ef07c5','af2b80f1-fcf1-40b4-b30d-dcecf21a8ea5',70,'text','Sự thay đổi về mặt ngôn từ này đánh trúng tâm lý hoang mang, lo sợ của bệnh nhân ngay khi họ vừa bước xuống khỏi ghế điều trị, biến sản phẩm thành một phần bắt buộc phải có trong "đơn thuốc" hậu phẫu.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('2045ed59-f60c-4df5-a0a1-8125d9f7a33d','19-education-product','2b6a7bc4-0c7e-44a0-9a68-28e1ba8d4db8',3,'Sơ đồ kiến trúc một bộ product kit tiêu chuẩn (Smile Care Kit)','so-o-kien-truc-mot-bo-product-kit-tieu-chuan-smile-care-kit',32,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('5abbe5f9-e637-43df-b2ab-f7da0ba52480','2045ed59-f60c-4df5-a0a1-8125d9f7a33d',71,'text','Mỗi bộ Kit sản phẩm được trao tay khách hàng bắt buộc phải được thiết kế đồng bộ theo cấu trúc dòng chảy trải nghiệm dưới đây:',NULL,NULL,NULL,NULL,NULL);
