INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('81fbca32-e793-4270-a839-4d12d07f0cf8','a983ca10-f1c6-412b-9969-21c5a6621892',73,'text','Dưới đây là bảng cấu trúc đóng gói 3 bộ sản phẩm chủ lực được chuẩn hóa theo logic của hệ điều hành **Dental Empire OS**, sẵn sàng đưa vào vận hành tại quầy Lễ tân:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('481ffe08-cc50-490b-9d83-60a7fac3cc73','a983ca10-f1c6-412b-9969-21c5a6621892',74,'image',NULL,'book/19-education-product/bcd4a9c3-8120-4072-8cb1-e488d56fb60a-img10.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('ae50184a-3217-4667-a8d5-cf5203962b9b','19-education-product','a983ca10-f1c6-412b-9969-21c5a6621892',4,'Bộ chỉ số kpi đo lường hiệu suất và mối liên kết hệ thống','bo-chi-so-kpi-o-luong-hieu-suat-va-moi-lien-ket-he-thong',34,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('ada5f7bd-6264-4c92-af67-d6c3e1f31d81','ae50184a-3217-4667-a8d5-cf5203962b9b',75,'text','Để biết phân hệ Sản phẩm đang đóng góp thực tế vào trục tăng trưởng hay chỉ là một danh mục bổ sung danh nghĩa, Dashboard dữ liệu của **Patient OS** bắt buộc phải theo dõi các chỉ số đo lường tài chính và hành vi sau:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('95c9d2c0-02ae-40f6-bb6e-1d7b942221a4','ae50184a-3217-4667-a8d5-cf5203962b9b',76,'text','\\text{Product Conversion Rate} = \\left( \\frac{\\text{Số bộ sản phẩm bán ra}}{\\text{Tổng số ca hoàn tất điều trị}} \\right) \\times 100\\%',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('60f43f8c-9e9b-4f19-998d-79d1bb79baf4','ae50184a-3217-4667-a8d5-cf5203962b9b',77,'text','- **Tỷ lệ mua lại (Repurchase Rate):** Thước đo phản ánh thói quen tiêu dùng của bệnh nhân. Nếu khách hàng quay lại phòng khám hoặc nhắn tin qua Zalo OA để mua tuýp kem đánh răng thứ 2, thứ 3, hệ thống đã thành công trong việc ghim thương hiệu vào đời sống của họ.- **Doanh thu từ khách cũ (Revenue from Old Patients):** Tỷ trọng doanh thu bán lẻ sản phẩm đóng góp bao nhiêu % vào tổng dòng tiền hữu cơ của phòng khám hằng tháng (Mục tiêu tiêu chuẩn đạt từ 5% - 10% tổng doanh thu hệ thống).- **Tỷ lệ chuyển đổi từ Sản phẩm sang Membership:** Đo lường số lượng bệnh nhân sau khi sử dụng các bộ Kit sản phẩm thấy hiệu quả và quyết định xuống tiền mua các gói thẻ hội viên chăm sóc trọn năm để hưởng đặc quyền dài hạn.',NULL,NULL,NULL,NULL,NULL);
