INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('d37d3f35-3fa2-4d18-a0c9-5083afbf8a95','683b66a6-8f07-42fc-a35c-cebde4c3382c',79,'text','Tạo ra một dòng tiền đều đặn, biên lợi nhuận thuần cao mà không bị giới hạn bởi thời gian làm việc của Bác sĩ hay số lượng ghế nha hiện tại.',NULL,NULL,NULL,NULL,NULL);
