INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('29a05f34-8737-4c85-a801-b070a5b1c58d','683b66a6-8f07-42fc-a35c-cebde4c3382c',81,'text','Bệnh nhân không phải tự bơi ngoài thị trường để tìm mua các loại bàn chải, kem đánh răng không rõ nguồn gốc. Họ được bao bọc trong một quy trình chăm sóc y khoa khép kín, an toàn tuyệt đối.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('6db7572b-b777-4cf7-b12b-d48e3f4dcb49','683b66a6-8f07-42fc-a35c-cebde4c3382c',82,'text','**6.3 Tăng nhận diện thương hiệu trong đời sống thực tế:**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('7df5fdb9-e277-4ce6-bfac-8f4f68c7b3c5','683b66a6-8f07-42fc-a35c-cebde4c3382c',83,'text','Logo, màu sắc và thông điệp của nha khoa xuất hiện liên tục trong không gian riêng tư của khách hàng hằng ngày, biến thương hiệu thành một phần thói quen của họ.',NULL,NULL,NULL,NULL,NULL);
