INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('249e6a48-2f77-4374-9b85-dc4d9ca64acf','683b66a6-8f07-42fc-a35c-cebde4c3382c',85,'text','Những hành động mở hộp (Unboxing), video hướng dẫn sử dụng sản phẩm thực tế từ Bác sĩ trở thành nguồn tư liệu nội dung vô tận, có tính giáo dục cao cho mạng lưới **Media Network**.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('421525d5-e3a7-48a0-99ba-336e88ec859b','683b66a6-8f07-42fc-a35c-cebde4c3382c',86,'text','**6.5 Giảm thiểu tối đa tỷ lệ biến chứng lâm sàng:**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('e6672e9e-cceb-45eb-bbbe-c3888e1cad19','683b66a6-8f07-42fc-a35c-cebde4c3382c',87,'text','Bệnh nhân tự chăm sóc răng đúng cách tại nhà giúp bảo vệ 100% tuổi thọ của răng sứ, trụ Implant hay cung niềng, từ đó bảo vệ uy tín chuyên môn cho hệ thống phòng khám.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('56c1ca40-514c-4e06-8a02-ebe24df618bc','683b66a6-8f07-42fc-a35c-cebde4c3382c',88,'text','**6.6 Nâng tầm định vị chuyên nghiệp:**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('0f05a125-5805-4f12-b200-b7c8e0dbef7b','683b66a6-8f07-42fc-a35c-cebde4c3382c',89,'text','Biến phòng khám RHM của bạn trong mắt khách hàng từ một tiệm "nhổ răng, trám răng" tầm thường trở thành một Viện chăm sóc sức khỏe nụ cười đẳng cấp, tử tế và toàn diện.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('e298c86a-577c-42a1-8677-4b543500cb49','19-education-product','a983ca10-f1c6-412b-9969-21c5a6621892',4,'Bản kế hoạch hành động ưu tiên 30 ngày cho khối vận hành','ban-ke-hoach-hanh-ong-uu-tien-30-ngay-cho-khoi-van-hanh',36,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('2fa01a99-70bf-4536-839e-6e3b08f50b92','e298c86a-577c-42a1-8677-4b543500cb49',90,'text','Để triển khai thành công phân hệ Sản phẩm hóa mà không gây nhiễu loạn bộ máy nhân sự hiện tại, Nhà quản trị áp dụng chiến lược cuốn chiếu theo lộ trình 3 bước sau:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('9ab67746-f5d8-4371-8c6b-e5144c766520','e298c86a-577c-42a1-8677-4b543500cb49',91,'text','- **Bước 1 (Ngày 1 - 10): Tập trung vào 3 nhóm Kit cốt lõi:** Đóng gói hoàn thiện bộ *30-Day Ortho Kit* (cho tệp niềng răng), *Implant Shield 6M* (cho tệp ca lớn) và *Post-Treatment Recovery* (cho tệp tổng quát). Đây là 3 nhóm dễ giải thích, dễ bán tại quầy Lễ tân và có nhu cầu thật cao nhất.- **Bước 2 (Ngày 11 - 20): Thiết lập bao bì và mã số hóa:** Tiến hành thiết kế hộp đựng Kit sang trọng, in cẩm nang hướng dẫn vật lý kèm mã QR link trực tiếp đến các video Bác sĩ hướng dẫn trên website. Cài đặt mã sản phẩm và luồng theo dõi tồn kho lên CRM hệ thống.- **Bước 3 (Ngày 21 - 30): Đào tạo Sales Script và Gắn KPI:** Tổ chức buổi đào tạo nội bộ cho Lễ tân, Trợ thủ và CSKH về kịch bản bóc tách điểm đau để tư vấn bộ Kit sản phẩm như một chỉ định y khoa hậu điều trị. Gắn chỉ số hiệu suất bán sản phẩm vào Dashboard theo dõi hằng tuần để thưởng phạt phân minh.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('86b5ccae-a3ef-41b0-a9f3-870585ed5b2c','e298c86a-577c-42a1-8677-4b543500cb49',92,'text','Chúng ta đã đóng gói hoàn chỉnh cấu trúc vận hành của phân hệ **Sản phẩm hóa**. Tiếp theo trong trục dọc của tầng *Education / Product Layer*, chúng ta sẽ bước sang **Phân hệ 15.8: Tổ chức Hội thảo tri thức (Workshop Engine)** nhằm biến không gian sảnh chờ của phòng khám thành một cái phễu thu hút khách hàng tiềm năng diện rộng.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('a27c0037-362c-432f-b20a-93042f5bb737','19-education-product',NULL,2,'19.6 Phân hệ Workshop Engine','196-phan-he-workshop-engine',37,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('f9c99326-0847-41ca-8f26-e3663d9fbcca','a27c0037-362c-432f-b20a-93042f5bb737',93,'text','**Biến sảnh chờ nha khoa thành phễu truyền thông và sân khấu uy tín chuyên gia**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('1dae7c0c-395b-4cd1-bece-8fce13bc86c8','a27c0037-362c-432f-b20a-93042f5bb737',94,'text','Trong thiết kế truyền thống, sảnh chờ của một phòng khám RHM thường là một không gian "chết" nơi bệnh nhân ngồi lướt điện thoại trong sự sốt ruột và lo lắng trước khi vào phòng điều trị. Nhà quản lý nha khoa thông thường chỉ xem sảnh chờ là nơi bố trí bàn ghế và tủ trưng bày sản phẩm.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('5a87a745-84bd-43ea-9482-4c7f4be7713e','a27c0037-362c-432f-b20a-93042f5bb737',95,'text','Hệ điều hành **Dental Empire OS** tái định nghĩa kiến trúc này: **Sảnh chờ nha khoa là một không gian giáo dục (Educational Space) và là một cái phễu thu hút, chuyển đổi lead tự nhiên có biên lợi nhuận cao nhất.**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('960ecb2b-fbee-478f-a53e-1f6b2465254b','a27c0037-362c-432f-b20a-93042f5bb737',96,'text','**Workshop Engine** chính là phân hệ chuyển hóa toàn bộ không gian vật lý hoặc phòng họp trực tuyến (Zoom/Hybrid) thành một sân khấu trình diễn năng lực chuyên gia. Thay vì chạy theo các chiến dịch quảng cáo đại trà để "bắt" khách hàng, chúng ta dùng tri thức sạch để thu hút bộ tộc khách hàng. Khi phòng khám chủ động giáo dục thị trường, bạn không chỉ bẻ gãy mọi pháo đài hoài nghi trước điều trị, mà còn kích hoạt một động cơ sản sinh dòng khách tái khám, hội viên và giới thiệu liên tục.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('f1408b71-44c1-42b0-a55d-101bee72569b','19-education-product','a27c0037-362c-432f-b20a-93042f5bb737',3,'Ma trận 6 mô hình workshop nha khoa thực chiến','ma-tran-6-mo-hinh-workshop-nha-khoa-thuc-chien',38,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('1e578638-4e9d-4254-8cd3-8ab26f4dff73','f1408b71-44c1-42b0-a55d-101bee72569b',97,'text','Tùy thuộc vào mục tiêu chiến lược hằng tháng, khối *Marketing OS* phối hợp cùng *Patient OS* để kích hoạt 1 trong 6 mô hình Workshop chuẩn hóa dưới đây:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('7de20645-ab7e-4207-a035-492a114b64f7','f1408b71-44c1-42b0-a55d-101bee72569b',98,'text','- **Workshop Chăm sóc cơ bản (Oral Wellness Basics):** Phễu thu hút lead lạnh diện rộng. Hướng tới đối tượng phụ huynh, người đi làm văn phòng muốn học cách vệ sinh răng miệng đúng chuẩn, phòng ngừa bệnh lý quanh răng.- **Workshop Chuyên môn sâu (Indication-Focused Seminar):** Phễu bẻ gãy hoài nghi cho các dịch vụ giá trị cao. Chia tách riêng biệt theo từng nhóm nhu cầu: Chuyên đề Implant, Ngày hội niềng răng, Tọa đàm răng sứ thẩm mỹ. Mỗi nhóm sẽ đi sâu vào giải quyết một "nỗi sợ hãi sinh học" cụ thể của tệp khách đó.- **Workshop Nha học đường & Phụ huynh (Kids Smile Academy):** Vũ khí chiếm lĩnh tệp nha khoa gia đình. Giáo dục thói quen, chế độ dinh dưỡng và kỹ thuật chăm sóc răng trẻ em tại nhà, giúp phụ huynh nhận biết thời điểm vàng chỉnh nha tăng trưởng.- **Workshop Tuân thủ hậu điều trị (Post-Treatment Compliance):** Thiết kế riêng cho bệnh nhân đang điều trị ca lớn (niềng răng, implant). Mục tiêu là tăng tỷ lệ tuân thủ phác đồ bảo tồn, giảm thiểu rủi ro biến chứng lâm sàng và cam kết lịch hẹn quay lại đúng chu kỳ.- **Workshop Cộng đồng theo chủ đề (Monthly Tribe Meetup):** Tổ chức định kỳ theo tháng/quý. Kết hợp giữa chia sẻ Case Study thực tế, hoạt động hỏi đáp trực tiếp (Q&A) và mini-checkup (khám tầm soát nhanh tại chỗ) để tạo traffic tự nhiên cho phòng khám.- **Workshop VIP Khép kín (Private Connoisseur Circle):** Giới hạn từ 10 - 15 khách hàng hiện hữu có chỉ số LTV cao hoặc nhóm khách hàng tiềm năng thượng lưu. Đây là không gian sang trọng để tri ân, gắn kết cảm xúc và mở đường cho việc chốt các gói Membership cao cấp hoặc sản phẩm Homecare độc quyền.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('3335d103-a948-4256-bedb-3166b48791fa','19-education-product','a27c0037-362c-432f-b20a-93042f5bb737',3,'Chiến lược định vị chủ đề: tấn công đích danh điểm đau','chien-luoc-inh-vi-chu-e-tan-cong-ich-danh-iem-au',39,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('3d907a0d-2b44-44c2-a05b-ab08f6539225','3335d103-a948-4256-bedb-3166b48791fa',99,'text','Quy tắc tối thượng của hệ thống: **Tuyệt đối không đặt tên chủ đề chung chung theo kiểu học thuật giáo điều.** Khách hàng không rảnh để đến nghe một bài giảng y khoa khô khan. Họ chỉ dành thời gian cho những chương trình hứa hẹn giải quyết trực tiếp một vấn đề nhức nhối hoặc một nỗi lo sợ thực tế mà họ đang đối mặt.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('82f2fe3b-0d6f-43ac-8fb6-186f2f01abd9','3335d103-a948-4256-bedb-3166b48791fa',100,'image',NULL,'book/19-education-product/8d7095c5-472a-4757-99d0-ded10362c0fd-img11.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('0af038cc-6fa4-4e8b-b388-5361d7868d08','3335d103-a948-4256-bedb-3166b48791fa',101,'text','- *Lỗi phổ biến:* "Tìm hiểu về kỹ thuật cấy ghép Implant nha khoa".- *Tiêu chuẩn Dental OS:* **"Mất răng lâu năm: Làm sao cấy Implant an toàn, ăn nhai bền vững mà không lo đau buốt?"**',NULL,NULL,NULL,NULL,NULL);
