INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('94500de3-8ac8-408d-ad4f-778160394ff4','7335cb18-0e2c-474a-97da-def1e2177e08',104,'text','Lựa chọn một chủ đề hẹp, đánh trúng điểm đau thực tế. Thực hiện quét CRM để gửi thư mời đích danh cho đúng tệp đối tượng quan tâm (Tuyệt đối không spam đại trà).',NULL,NULL,NULL,NULL,NULL);
