INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('f70944d2-e1cb-411d-9175-7cf7f2eead07','7335cb18-0e2c-474a-97da-def1e2177e08',106,'text','Mở cổng đăng ký qua Zalo OA/Website. Giới hạn số lượng chỗ ngồi (Scarcity) để tạo độ khan hiếm và đẩy cao giá trị của buổi chia sẻ tri thức.',NULL,NULL,NULL,NULL,NULL);
