INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('eadf31f6-e84b-4cf7-b87d-2f34c728365b','7335cb18-0e2c-474a-97da-def1e2177e08',108,'text','Bác sĩ phụ trách chuyên môn trực tiếp chia sẻ kiến thức cốt lõi ngắn gọn trong 15 - 20 phút bằng ngôn từ bình dân, trực quan, loại bỏ thuật ngữ y khoa phức tạp.',NULL,NULL,NULL,NULL,NULL);
