INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('b88654c2-ac29-4a6e-8a98-0eaed6c74d00','7335cb18-0e2c-474a-97da-def1e2177e08',112,'text','Mở cổng hỏi đáp trực tiếp giữa Bác sĩ và người tham dự. Đây là thời điểm vàng để Bác sĩ phô diễn năng lực chuyên môn tầng sâu và sự thấu cảm y đức.',NULL,NULL,NULL,NULL,NULL);
