INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('5db34cab-a7b3-4af9-a708-6fcd6ee32db9','7335cb18-0e2c-474a-97da-def1e2177e08',114,'text','Điều hướng toàn bộ người tham dự vào khu vực ghế nha để thực hiện mini-checkup, chụp phim tầm soát nhanh và đưa ra lời khuyên cá nhân hóa ngay tại chỗ.',NULL,NULL,NULL,NULL,NULL);
