INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('80c93beb-1ea1-4a38-a57a-6a0d86322fc4','7335cb18-0e2c-474a-97da-def1e2177e08',116,'text','Chốt lịch hẹn chính thức, hướng dẫn đăng ký gói Membership đặc quyền hoặc trao tay bộ sản phẩm Homecare Kit ngay tại quầy Lễ tân trước khi khách ra về.',NULL,NULL,NULL,NULL,NULL);
