INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('5c8ece09-c0b3-49d6-8337-acbeb3d0d92d','96cc9d07-80ad-4398-9f1f-c36ac1ee5e58',117,'text','Một buổi Workshop thành công không được đo bằng tiếng vỗ tay, nó phải được định lượng minh bạch qua các chỉ số trên Dashboard của *Marketing OS* và *Patient OS*:',NULL,NULL,NULL,NULL,NULL);
