INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('4db643a0-141a-4ef7-ae25-34b624c7a2bc','19-education-product','96cc9d07-80ad-4398-9f1f-c36ac1ee5e58',4,'Sản phẩm hoàn chỉnh: 1-page workshop implementation blueprint','san-pham-hoan-chinh-1-page-workshop-implementation-blueprint',42,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('ef708358-faa8-46cb-bc96-32eb266200d5','4db643a0-141a-4ef7-ae25-34b624c7a2bc',119,'text','Dưới đây là Bản kịch bản thực địa trọn gói trên 1 trang giấy, được thiết kế tối ưu cho chủ đề chủ lực: **"Chăm sóc răng sau điều trị: 5 lỗi thường gặp và cách phòng tránh"**. Toàn bộ đội ngũ từ MC, Lễ tân cho đến Bác sĩ có thể dùng để thực thi ngay lập tức.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('b317c5b4-56d8-47bc-b46c-ec6c35a841a5','19-education-product','96cc9d07-80ad-4398-9f1f-c36ac1ee5e58',4,'📋 BẢN KẾ HOẠCH TRIỂN KHAI WORKSHOP THỰC ĐỊA (1-PAGE DOCUMENT)','ban-ke-hoach-trien-khai-workshop-thuc-ia-1-page-document',43,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('7c9c7c97-5ecc-4257-83dc-bf31328fc503','b317c5b4-56d8-47bc-b46c-ec6c35a841a5',120,'text','- **Tên Sự Kiện:** Workshop Tri Thức Số 04: Chăm sóc răng sau điều trị — 5 sai lầm chí mạng và giải pháp bảo tồn nụ cười từ chuyên gia.- **Đối Tượng Mục Tiêu:** Bệnh nhân vừa hoàn tất ca lâm sàng tổng quát/thẩm mỹ, người nhà bệnh nhân và khách hàng tiềm năng đang do dự trên Media Network.- **Thời Lượng:** Đúng 60 phút (Khung giờ vàng: Thứ Bảy từ 15:00 - 16:00).- **Địa Điểm:** Sảnh chờ Khu VIP Nha khoa Thích Làm Răng.- **Chuyên Gia Trình Bày:** Bác sĩ Nguyễn Phước Vinh',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('f61c7813-ea53-47ee-bbb7-9afc037b84d9','b317c5b4-56d8-47bc-b46c-ec6c35a841a5',121,'image',NULL,'book/19-education-product/3fb5d73a-e6a3-4066-9eef-03d23f6fa334-img13.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('2edd77f7-17fe-47ff-b5bb-1acef32ab083','19-education-product','96cc9d07-80ad-4398-9f1f-c36ac1ee5e58',4,'🎯 Chiến lược lời gọi hành động (CTA - Call to action matrix)','chien-luoc-loi-goi-hanh-ong-cta-call-to-action-matrix',44,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('e1cf59a5-92ca-4bb9-ae87-8c4077010738','2edd77f7-17fe-47ff-b5bb-1acef32ab083',122,'text','Tuyệt đối không kết thúc buổi workshop bằng một câu cảm ơn suông rồi giải tán. Đội ngũ lễ tân phải túc trực sẵn tại quầy với 3 gói chuyển đổi mục tiêu:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('4c25bc56-c548-4607-a140-3fcd35af521e','2edd77f7-17fe-47ff-b5bb-1acef32ab083',123,'text','- **CTA 1 (Dành cho khách cũ):** Kích hoạt lệnh đặt lịch hẹn `Confirmed_Recall` cho chu kỳ bảo dưỡng kế tiếp, ký xác nhận vào sổ theo dõi lâm sàng.- **CTA 2 (Dành cho khách tiềm năng):** Điều hướng vào phòng chụp phim tầm soát, tạo hồ sơ bệnh án mới trên CRM, gắn tag `Lead_From_Workshop`.- **CTA 3 (Dành cho nhóm gia đình):** Chốt gói hội viên trả trước *Family Healthcare Pass* với đặc quyền bao bọc nụ cười cho cả tổ ấm trọn năm.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('40e9f452-d3e0-4159-befb-4d8af4a4dafb','2edd77f7-17fe-47ff-b5bb-1acef32ab083',124,'text','**Mantra vận hành Workshop Engine:***"Sảnh chờ của nha khoa không được thiết kế để bệnh nhân chờ đợi bác sĩ. Nó được thiết kế để tri thức y khoa thay thế bác sĩ bẻ gãy mọi sự hoài nghi của khách hàng trước khi họ bước lên ghế điều trị."*',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('1480799e-5189-4611-927f-dbc8894f0623','19-education-product',NULL,2,'19.7 Phân hệ tài liệu số (Digital Assets Library)','197-phan-he-tai-lieu-so-digital-assets-library',45,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('2c1f5260-2a43-4d58-8f7d-6562df523c45','1480799e-5189-4611-927f-dbc8894f0623',125,'text','**Vật chất hóa tri thức y khoa thành tài sản doanh nghiệp trường tồn**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('64ba20a0-8a01-4d16-8bf4-62fc66f434c1','1480799e-5189-4611-927f-dbc8894f0623',126,'text','Trong hoạt động tư vấn nha khoa truyền thống, một trong những lỗ hổng lớn nhất gây rò rỉ tỷ lệ chốt và làm sụt giảm trải nghiệm bệnh nhân là **Sự tam sao thất bản của thông tin**. Khi Bác sĩ dặn dò bằng miệng, bệnh nhân chỉ nhớ được khoảng 30\\% lượng kiến thức khi về đến nhà. Khi Trợ thủ giải thích quy trình, sự chuẩn xác phụ thuộc hoàn toàn vào tâm trạng và năng lực của nhân sự ngày hôm đó. Điều này khiến phòng khám bị phụ thuộc nặng nề vào con người và không thể chuẩn hóa tiêu chuẩn dịch vụ.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('44d5b38c-f5ee-4041-8f4c-cd74911f40e1','1480799e-5189-4611-927f-dbc8894f0623',127,'text','Trong kiến trúc **Dental Empire OS**, chúng tôi không để tri thức y khoa tồn tại dưới dạng lời nói vô hình. Toàn bộ chuyên môn, kinh nghiệm điều trị và phác đồ lâm sàng của phòng khám bắt buộc phải được **vật chất hóa thành Hệ thống Tài liệu số (Digital Assets Library)**.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('2d9b9eb4-3cb3-44e3-b188-122d66f68ef9','1480799e-5189-4611-927f-dbc8894f0623',128,'text','Hệ thống tài liệu này đóng vai trò như một "thư viện tri thức có cấu trúc", được lưu trữ đồng bộ để tái sử dụng làm vũ khí cho 4 mặt trận vận hành: Tư vấn tại ghế, Chăm sóc hậu điều trị, Tổ chức Workshop và làm nguyên liệu sạch cho khối truyền thông. Khi phòng khám sở hữu một thư viện tài liệu xuất sắc, bạn đang cho phép bệnh nhân "tự giáo dục" và chủ động phá bỏ các rào cản tâm lý trước khi gặp Bác sĩ.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('265fbc2d-ebcb-4051-9dec-0556dfcd5b44','19-education-product','1480799e-5189-4611-927f-dbc8894f0623',3,'Kiến trúc phân loại 4 nhóm tài liệu trong hệ sinh thái nha khoa','kien-truc-phan-loai-4-nhom-tai-lieu-trong-he-sinh-thai-nha-khoa',46,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('736dbdce-921e-400f-ad4d-2eedf0749c6d','265fbc2d-ebcb-4051-9dec-0556dfcd5b44',129,'text','Thư viện tài sản tri thức của hệ thống **Thích Làm Răng** được tổ chức khoa học thành 4 nhóm chức năng riêng biệt để phục vụ chính xác từng giai đoạn trên hành trình trải nghiệm:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('94a07664-15ab-418b-8ee6-4a18cec63b10','19-education-product','265fbc2d-ebcb-4051-9dec-0556dfcd5b44',5,'Nhóm I: Tài liệu giáo dục trước quyết định (Pre-purchase Assets)','nhom-i-tai-lieu-giao-duc-truoc-quyet-inh-pre-purchase-assets',47,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('7d99b999-84b2-4bfc-bab7-8066a215ed61','94a07664-15ab-418b-8ee6-4a18cec63b10',130,'text','- **Mục tiêu:** Tấn công trực diện vào pháo đài hoài nghi của lead lạnh và lead ấm, cung cấp tri thức thường thức để khách hàng tự nhận biết vấn đề và gia tăng độ tin tưởng tuyệt đối trước khi mua dịch vụ.- **Hình thức:** Hướng dẫn tổng quan, cẩm nang trước điều trị, bộ câu hỏi thường gặp (FAQ), tài liệu Case Study Trước - Sau.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('9ed65544-b5cb-45ac-bf57-f02d9aa6e4d8','19-education-product','265fbc2d-ebcb-4051-9dec-0556dfcd5b44',5,'Nhóm II: Tài liệu chăm sóc hậu điều trị (Post-treatment Assets)','nhom-ii-tai-lieu-cham-soc-hau-ieu-tri-post-treatment-assets',48,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('81f97a7c-ead9-4646-badd-25161565ac57','9ed65544-b5cb-45ac-bf57-f02d9aa6e4d8',131,'text','- **Mục tiêu:** Mỏ neo giữ chân khách hàng sau khi rời ghế nha, giảm thiểu tối đa tỷ lệ biến chứng lâm sàng và tự động điều hướng khách hàng quay lại theo đúng lịch hẹn Recall.- **Hình thức:** Cẩm nang dặn dò sau can thiệp, checklist hành động hằng ngày, tài liệu chuyên sâu cho nhóm bệnh nhân đặc thù (Niềng răng, Implant).',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('f8956e69-e1fb-40a7-a59a-4b0bdb190131','19-education-product','265fbc2d-ebcb-4051-9dec-0556dfcd5b44',5,'Nhóm III: Tài liệu hỗ trợ cộng đồng và Workshop (Community &amp; Event Assets)','nhom-iii-tai-lieu-ho-tro-cong-ong-va-workshop-community-amp-event-assets',49,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('00819960-eec7-4e20-a3f8-12c68f884dab','f8956e69-e1fb-40a7-a59a-4b0bdb190131',132,'text','- **Mục tiêu:** Gia tăng chỉ số tương tác (Engagement) bên trong các nhóm Micro-Communities, biến tri thức thành thứ tài sản có giá trị cao để bệnh nhân tự hào mang đi chia sẻ (Kích nổ Referral).- **Hình thức:** Booklet sự kiện, sách tay Membership giới thiệu đặc quyền, cẩm nang hướng dẫn sức khỏe gia đình.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('fcedc3cc-f8a1-45a3-9c3e-4699b33c5e0a','19-education-product','265fbc2d-ebcb-4051-9dec-0556dfcd5b44',5,'Nhóm IV: Tài liệu vận hành nội bộ (Internal Operational Assets)','nhom-iv-tai-lieu-van-hanh-noi-bo-internal-operational-assets',50,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('f9343748-1106-4141-b46d-9c54e78af064','fcedc3cc-f8a1-45a3-9c3e-4699b33c5e0a',133,'text','- **Mục tiêu:** Giải phóng sự phụ thuộc vào ngôi sao nhân sự, chuẩn hóa năng lực tư vấn của toàn bộ đội ngũ Lễ tân, Trợ thủ và Chuyên viên tư vấn.- **Hình thức:** Script kịch bản xử lý câu hỏi khó, quy trình giải thích phác đồ chuẩn SLA, checklist bàn giao lâm sàng hậu phẫu.',NULL,NULL,NULL,NULL,NULL);
