INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('ab588f96-3986-43a0-8d11-30f3ff2f4ddb','19-education-product','82d747e0-4b86-4fbf-bf62-bfa9332c5432',4,'Chuẩn hóa năng lực tư vấn tuyệt đối: Toàn bộ nhân sự từ Lễ tân, Trợ thủ cho đến Chuyên viên tư vấn đều sử dụng chung một ngôn ngữ, một tiêu chuẩn tri thức khi giải thích cho khách hàng, triệt tiêu 100% lỗi sai do con người.','chuan-hoa-nang-luc-tu-van-tuyet-oi-toan-bo-nhan-su-tu-le-tan-tro-thu-cho-en-chuy',55,'[]');
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('40d46aab-6ff8-4a97-9ee0-5d386956aec6','19-education-product','82d747e0-4b86-4fbf-bf62-bfa9332c5432',4,'Giải phóng và giảm phụ thuộc vào nhân sự: Tài liệu thay thế con người thực hiện các tác vụ giáo dục lặp đi lặp lại. Nhân sự mới vào chỉ cần đọc thuộc lòng thư viện tài sản là có thể tự tin tiếp khách chuẩn SLA.','giai-phong-va-giam-phu-thuoc-vao-nhan-su-tai-lieu-thay-the-con-nguoi-thuc-hien-c',56,'[]');
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('c9fd9b63-c625-42e8-94ad-4c300f12dc3e','19-education-product','82d747e0-4b86-4fbf-bf62-bfa9332c5432',4,'Tăng tỷ lệ chuyển đổi phác đồ lớn: Khi bệnh nhân được cung cấp tài liệu chuyên sâu, có cấu trúc khoa học trước buổi khám, họ đã tự bẻ gãy mọi hoài nghi hoang mang, đẩy tốc độ ra quyết định đồng ý điều trị lên nhanh gấp 3 lần.','tang-ty-le-chuyen-oi-phac-o-lon-khi-benh-nhan-uoc-cung-cap-tai-lieu-chuyen-sau-c',57,'[]');
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('8b954185-98f3-4876-844a-e357f8d501ac','19-education-product','82d747e0-4b86-4fbf-bf62-bfa9332c5432',4,'Thiết lập định vị chuyên nghiệp đẳng cấp: Biến phòng khám RHM của bạn thành một tổ chức y khoa có chiều sâu tri thức, vượt trội hoàn toàn so với các phòng khám đối thủ chỉ biết nói suông và chèo kéo giảm giá.','thiet-lap-inh-vi-chuyen-nghiep-ang-cap-bien-phong-kham-rhm-cua-ban-thanh-mot-to-',58,'[]');
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('5072db7f-150a-4a19-af48-a316257fc36f','19-education-product','82d747e0-4b86-4fbf-bf62-bfa9332c5432',4,'Tạo nguồn nhiên liệu sạch cho Media Network: Mỗi trang tài liệu, mỗi câu hỏi trong bộ FAQ chính là một kịch bản quay video ngắn hoàn hảo cho TikTok hoặc bài viết chuẩn SEO cho website','tao-nguon-nhien-lieu-sach-cho-media-network-moi-trang-tai-lieu-moi-cau-hoi-trong',59,'[]');
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('5842a130-f9e2-4e62-a5de-6387911ba965','19-education-product','82d747e0-4b86-4fbf-bf62-bfa9332c5432',4,'Kích nổ dòng Referral tự động: Biến những lời giới thiệu truyền miệng vô hình thành hành động trao tay những cuốn cẩm nang tri thức hữu hình, giúp dòng lead mới tự động đổ về ghế nha một cách tự nhiên.','kich-no-dong-referral-tu-ong-bien-nhung-loi-gioi-thieu-truyen-mieng-vo-hinh-than',60,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('7c220016-d1e1-43bc-8c3e-e1ed679c1253','5842a130-f9e2-4e62-a5de-6387911ba965',151,'text','**Mantra tối thượng của Phân hệ:***"Lời nói của bác sĩ có thể bay đi theo gió, nhưng một cuốn cẩm nang tri thức được đóng gói bài bản sẽ ở lại trong ngôi nhà của khách hàng qua nhiều năm tháng, âm thầm bảo vệ nụ cười của họ và liên tục dắt người thân của họ quay trở lại với phòng khám."*',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('023bc37c-3152-43d2-9304-15a122c029b0','19-education-product',NULL,2,'19.8 Phân hệ đào tạo thực chiến (Training Engine)','198-phan-he-ao-tao-thuc-chien-training-engine',61,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('a9811f7c-5516-4050-9471-b2c2da53529c','023bc37c-3152-43d2-9304-15a122c029b0',152,'text','**Đóng gói chất xám, chuẩn hóa đội ngũ và kiến tạo thị trường mục tiêu**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('eac6b16a-4606-4250-9c23-6b3d186e3f4e','023bc37c-3152-43d2-9304-15a122c029b0',153,'text','Trong một doanh nghiệp nha khoa vận hành theo cảm tính, "đào tạo" thường là một khái niệm xa xỉ hoặc bị hiểu sai thành những buổi nhắc nhở rập khuôn của chủ phòng khám khi có sự cố xảy ra. Nhân sự mới vào được bàn giao công việc theo kiểu "người cũ dắt người mới", dẫn đến việc mỗi nhân viên tiếp đón khách hàng một kiểu, tư vấn phác đồ một cách tùy tiện theo thói quen cá nhân. Sự lệch pha này trực tiếp phá hủy tính đồng nhất của Trải nghiệm bệnh nhân (Patient Experience) và làm sụp đổ uy tín thương hiệu.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('7b0f8954-9e22-45df-9b36-7bce1343122b','023bc37c-3152-43d2-9304-15a122c029b0',154,'text','Hệ điều hành **Dental Empire OS** định nghĩa lại tư duy cốt lõi này: **Đào tạo không phải là một hoạt động truyền khẩu ngắn hạn, đào tạo là quá trình đóng gói chất xám chuyên môn thành tài sản vận hành.**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('67b65f1f-16d1-45f7-9b17-d30490f68f5c','023bc37c-3152-43d2-9304-15a122c029b0',155,'text','Tại phân hệ **Training Engine** thuộc tầng *Education / Product Layer*, toàn bộ tri thức y khoa, kỹ năng lâm sàng và quy trình tiếp đón thực địa sẽ được số hóa thành các bộ Quy trình chuẩn (SOP), Playbook vận hành, kịch bản Role-play và nội dung giáo dục có khả năng nhân bản trọn đời. Hệ thống vận hành dựa trên kiến trúc **Đào tạo nhị phân (Binary Training Architecture)** gồm hai trục dọc hướng nội và hướng ngoại:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('dba6b86b-e74c-4feb-95af-fb2b30976f8b','023bc37c-3152-43d2-9304-15a122c029b0',156,'image',NULL,'book/19-education-product/bd3dfc7f-0392-4936-814a-76827c646111-img16.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('2836df10-253a-46b0-aa53-087241c7dba1','19-education-product','023bc37c-3152-43d2-9304-15a122c029b0',4,'Đào tạo nội bộ (internal training): đồng nhất ngôn ngữ và tiêu chuẩn sàn vận hành','ao-tao-noi-bo-internal-training-ong-nhat-ngon-ngu-va-tieu-chuan-san-van-hanh',62,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('5130ed7b-56c4-48a6-87b3-03471d8c7141','2836df10-253a-46b0-aa53-087241c7dba1',157,'text','Mục tiêu tối thượng của trục Đào tạo nội bộ là **Triệt tiêu tuyệt đối sự phụ thuộc vào ngôi sao nhân sự** và thiết lập một chỉ số Quản trị:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('34ed07a2-98df-4aea-8da1-d6ccf68207a4','2836df10-253a-46b0-aa53-087241c7dba1',158,'text','\\text{Chỉ số đồng nhất trải nghiệm (Uniformity Index)} \\rightarrow 100\\%',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('5f9752ef-5491-4186-94e2-84a0d8a608fd','2836df10-253a-46b0-aa53-087241c7dba1',159,'text','Mọi thành viên từ Lễ tân, Trợ thủ cho đến Bác sĩ điều trị đều phải nói cùng một ngôn ngữ thương hiệu, hành động theo cùng một tiêu chuẩn SLA khắt khe của hệ thống nha khoa **Thích Làm Răng**.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('e6b9ff9d-47fc-44ac-938c-4a7c286a1ccf','2836df10-253a-46b0-aa53-087241c7dba1',160,'text','**Các khối nội dung thực chiến bắt buộc phải Onboarding:**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('a180add2-7b00-46cb-82b9-a18098422e8c','2836df10-253a-46b0-aa53-087241c7dba1',161,'text','- **Kỹ thuật phá băng (Greeting Tech):** Quy chuẩn đón tiếp, cách mỉm cười, chào hỏi bằng tên riêng và kỹ thuật tạo thiện cảm trong 30 giây đầu tiên.- **Khai phá nhu cầu ẩn giấu (Needs Discovery):** Bộ câu hỏi khai thác nỗi đau thực tế và nhu cầu thẩm mỹ của bệnh nhân mà không gây ra áp lực thương mại tại sảnh chờ.- **Giảng thuật phác đồ thường thức (Treatment Plan Translation):** Kỹ thuật chuyển đổi thuật ngữ y khoa khô khan thành ngôn từ bình dân, trực quan giúp bệnh nhân hiểu và tin tưởng tuyệt đối.- **Hóa giải rào cản (Objection Handling):** Bộ kịch bản mẫu xử lý các câu hỏi nhạy cảm về giá thành cao, nỗi sợ đau sinh học hoặc nỗi sợ biến chứng rủi ro.- **Pipeline Follow-up & Thu hoạch giá trị:** Quy trình chăm sóc hậu tư vấn, cách xin đánh giá Google Maps/Zalo đúng thời điểm cảm xúc đỉnh cao (**Wow Peak**) và kỹ thuật kích hoạt dòng khách Referral tự nhiên.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('4f5e7107-30fd-47ce-b097-b3dabcfff0cc','19-education-product','023bc37c-3152-43d2-9304-15a122c029b0',4,'Đào tạo bên ngoài (external training): giáo dục thị trường và đẩy cao uy tín chuyên gia','ao-tao-ben-ngoai-external-training-giao-duc-thi-truong-va-ay-cao-uy-tin-chuyen-g',63,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('7bb18983-3d71-4c17-b8a5-be6d17d1d540','4f5e7107-30fd-47ce-b097-b3dabcfff0cc',162,'text','Nếu đào tạo hướng nội giúp bạn giữ chặt chân bệnh nhân cũ, thì đào tạo hướng ngoại chính là vũ khí hạng nặng để chiếm lĩnh tâm trí tệp khách hàng tiềm năng diện rộng. Đây là nơi phòng khám mở rộng giá trị vượt ra ngoài không gian của những chiếc ghế nha vật lý.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('67718f1b-b975-43c4-a487-8926223a537f','4f5e7107-30fd-47ce-b097-b3dabcfff0cc',163,'text','Bằng cách liên tục xuất bản các chương trình đào tạo cộng đồng, phòng khám tự động thiết lập một **Pháo đài uy tín chuyên gia (Authority Fortress)** cho Bác sĩ sáng lập Nguyễn Phước Vinh, biến thương hiệu thành một bộ tộc tri thức răng miệng đáng tin cậy.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('e872379b-697e-47f1-ab44-431e79503973','4f5e7107-30fd-47ce-b097-b3dabcfff0cc',164,'text','**Các hình thức đóng gói đào tạo hướng ngoại:**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('fb01a083-cc85-441f-a0ef-a637dbb4a2cf','4f5e7107-30fd-47ce-b097-b3dabcfff0cc',165,'text','- **Workshop Tri thức cộng đồng:** Các buổi học trực tiếp hoặc trực tuyến chia sẻ chuyên sâu theo từng nhóm dịch vụ chủ lực (Implant, Chỉnh nha tăng trưởng, Răng trẻ em).- **Webinar / Livestream Chuyên môn định kỳ:** Sân khấu trực tuyến tương tác, giải đáp trực tiếp các thắc mắc y khoa tầng sâu để sưởi ấm tệp lead lạnh trên mạng xã hội.- **Chuỗi Video Giáo dục ngắn (Short Video Series):** Hệ thống bài học rút gọn, dễ xem, dễ chia sẻ được phát sóng đồng bộ trên Media Network (TikTok, Facebook Reels).- **Booklet / Sách tay hướng dẫn thực địa:** Ấn phẩm tri thức vật lý trao tay bệnh nhân sau các buổi tư vấn để họ mang về nhà nghiên cứu và chia sẻ cho người thân.- **Hệ thống tài nguyên nội dung chuẩn SEO:** Kho bài viết đào tạo chuyên sâu trên website và Google Business Profile, tự động đánh chặn khi khách hàng chủ động tra cứu giải pháp trên internet.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('01aa1a87-6ae0-48ae-9359-7f5b22d91efa','19-education-product','023bc37c-3152-43d2-9304-15a122c029b0',4,'Bộ khung bắt buộc của một chương trình đào tạo tiêu chuẩn','bo-khung-bat-buoc-cua-mot-chuong-trinh-ao-tao-tieu-chuan',64,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('286986ca-6bc6-4878-9f54-433b8f240d47','01aa1a87-6ae0-48ae-9359-7f5b22d91efa',166,'image',NULL,'book/19-education-product/40eafa19-33a2-4333-bb1c-fd54b6b7afbd-img17.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('ae7827a0-50ca-4815-85f9-77d6a294e44f','01aa1a87-6ae0-48ae-9359-7f5b22d91efa',167,'text','Để một chương trình đào tạo không bị rơi vào trạng thái nói suông, lý thuyết suông, hệ điều hành quy định mọi tài liệu đào tạo được xuất bản bắt buộc phải có đầy đủ **7 cấu phần cấu trúc**:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('f03ad487-eb0b-48a5-b6ec-304c68fdcd70','01aa1a87-6ae0-48ae-9359-7f5b22d91efa',168,'text','- **Mục tiêu (Objectives):** Xác định rõ ràng kết quả hành vi hoặc chỉ số KPI cần thay đổi sau buổi học.- **Đối tượng học (Target Learners):** Chỉ định đích danh các bộ phận chức năng bắt buộc phải tham dự.- **Nội dung chính (Core Syllabus):** Khung kiến thức cốt lõi được chia nhỏ thành các module thực chiến.- **Người phụ trách (Owner):** Nhân sự chịu trách nhiệm chính về chất lượng đầu ra của buổi học.- **Tài liệu đi kèm (Handouts/Playbooks):** Các file SOP, Script mẫu hoặc Slide bài giảng phục vụ việc tra cứu.- **KPI đo lường hiệu quả (Metrics):** Chỉ số định lượng để kiểm tra năng lực áp dụng thực tế của học viên.- **Checklist triển khai (Deployment Checklist):** Các bước chuẩn bị cơ sở vật chất, công cụ kiểm tra đầu vào/đầu ra.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('40c51491-d334-454a-9b4b-fb559d0205eb','19-education-product','023bc37c-3152-43d2-9304-15a122c029b0',4,'Ma trận đóng gói 10 chương trình đào tạo tiêu chuẩn tại phòng khám rhm','ma-tran-ong-goi-10-chuong-trinh-ao-tao-tieu-chuan-tai-phong-kham-rhm',65,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('934e1275-847b-4a00-9d6d-0771efdccbe0','40c51491-d334-454a-9b4b-fb559d0205eb',169,'text','Dưới đây là Bản đồ ma trận 10 chương trình đào tạo cốt lõi được số hóa và lưu trữ sẵn trong thư viện tài sản của hệ điều hành **Dental Empire OS**:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('7748716f-c90f-402c-a212-41e6653f166f','40c51491-d334-454a-9b4b-fb559d0205eb',170,'image',NULL,'book/19-education-product/7187c2e2-654e-41c0-b46e-e79ce83c6e3b-img18.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('147530d8-2aa5-415d-bb5d-be513fd92729','19-education-product','023bc37c-3152-43d2-9304-15a122c029b0',4,'Cẩm nang hướng dẫn điều hành dành cho chủ phòng khám RHM','cam-nang-huong-dan-ieu-hanh-danh-cho-chu-phong-kham-rhm',66,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('8f791f86-4515-478b-9b1e-c0eae457caaf','147530d8-2aa5-415d-bb5d-be513fd92729',171,'text','Để phân hệ Đào tạo vận hành ra tiền thực tế, không bị biến thành những buổi họp hành lý thuyết suông gây mệt mỏi cho đội ngũ, Nhà quản trị bắt buộc phải áp dụng **Chiến lược cuốn chiếu và Cấu trúc buổi học 3 tầng** dưới đây:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('f40be24c-b57e-4693-8a86-48139d385cb2','147530d8-2aa5-415d-bb5d-be513fd92729',172,'text','**5.1 Nguyên tắc ưu tiên theo giai đoạn tăng trưởng:**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('6d5a17ff-25a8-4e0f-95c8-63b82a5920f4','147530d8-2aa5-415d-bb5d-be513fd92729',173,'text','- **Nếu phòng khám đang ở giai đoạn khởi nghiệp/vừa và nhỏ:** Hãy tập trung toàn lực đóng gói và huấn luyện nghiêm ngặt **5 chương trình đầu tiên (Từ STT 1 đến STT 5)**. Mục tiêu duy nhất giai đoạn này là ổn định bộ máy, chuẩn hóa sàn vận hành và tối ưu hóa tỷ lệ chốt tại ghế nha.- **Nếu phòng khám bước vào giai đoạn tăng trưởng quy mô/xây dựng chuỗi:** Phải kích hoạt ngay lập tức **các chương trình 7, 8 và 10**. Đây là những động cơ sản sinh ra vòng lặp Review, tạo dựng Bộ tộc cộng đồng và tự động khơi thông dòng khách Referral dồi dào có chi phí CAC bằng 0.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('bc469a08-8217-47a4-8b66-027f24947cb2','147530d8-2aa5-415d-bb5d-be513fd92729',174,'text','**5.2 Kỹ thuật tổ chức một buổi học chuẩn hiệu suất (The 3-Part Training Session):**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('00a199bd-9e12-4325-bfdd-c0cd36108b77','147530d8-2aa5-415d-bb5d-be513fd92729',175,'text','Mỗi buổi đào tạo nội bộ chỉ nên kéo dài tối đa 45 - 60 phút và bắt buộc phải được bóc tách cấu trúc theo đường ống tuyến tính sau:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('717c9764-0d82-47f5-9fc0-77e939caa3ed','147530d8-2aa5-415d-bb5d-be513fd92729',176,'text','- **Lọc sạch nhận thức hệ thống: ***Phần 1: Lý thuyết rút gọn (15 Phút).*',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('1b6a881a-7e21-4783-9d5e-26e32911f211','147530d8-2aa5-415d-bb5d-be513fd92729',177,'text','Người chịu trách nhiệm (Owner) chỉ trình bày bản chất cốt lõi của quy trình hoặc kịch bản mẫu. Tuyệt đối không nói lý thuyết suông dài dòng.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('e91d2a62-82bd-425c-840e-c63c2aae5ce5','147530d8-2aa5-415d-bb5d-be513fd92729',178,'text','- **Cọ xát tình huống thực tế:**Phần 2: *Thực địa Role-play (30 Phút).*',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('cd7e47fd-6171-4fcb-9a21-f728a85f3b1d','147530d8-2aa5-415d-bb5d-be513fd92729',179,'text','Chia cặp nhân sự đóng vai (Một người đóng bệnh nhân khó tính, một người đóng nhân viên tư vấn/lễ tân). Trực tiếp đối mặt, xử lý tình huống lâm sàng ngay tại chỗ dưới sự giám sát và hiệu chỉnh trực tiếp từ Bác sĩ trưởng ca.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('e156ecc7-3623-4787-86dd-aa33f8c12115','147530d8-2aa5-415d-bb5d-be513fd92729',180,'text','- **Ký duyệt nghiệm thu năng lực:**Phần 3: *Chốt chặn Checklist (15 Phút).*',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('680f830c-b30f-4cd1-9de0-55149e5ec8c2','147530d8-2aa5-415d-bb5d-be513fd92729',181,'text','Bàn giao bảng Checklist hành động thực tế hằng ngày cho từng nhân sự. Ký duyệt nghiệm thu đầu ra và chính thức cập nhật tài sản vào hệ thống quản trị chung.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('95cce052-512e-4c1d-be4f-031e53bdb857','19-education-product','023bc37c-3152-43d2-9304-15a122c029b0',4,'Kỷ luật mỏ neo KPI (No KPI - No Training):','ky-luat-mo-neo-kpi-no-kpi-no-training',67,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('21622994-113c-4223-86e4-ea090903e2ed','95cce052-512e-4c1d-be4f-031e53bdb857',182,'text','Tuyệt đối không đào tạo mà không gắn liền với một chỉ số định lượng cụ thể. Sau khi khép lại bất kỳ chương trình huấn luyện nào, Nhà quản trị bắt buộc phải cài đặt một mỏ neo KPI tương ứng trên Dashboard hệ thống để theo dõi hiệu suất thực thi của đội ngũ trong 30 ngày kế tiếp:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('49afaf74-fa28-4105-a0b9-6351c9b1b1e4','95cce052-512e-4c1d-be4f-031e53bdb857',183,'text','- *Đào tạo quy trình tiếp đón* ➔ Đo lường bằng chỉ số **Thời gian phản hồi khách hàng (Response Time)** và điểm hài lòng của khách tại quầy.- *Đào tạo xử lý từ chối và lo ngại giá* ➔ Đo lường trực tiếp bằng chỉ số **Tỷ lệ chốt phác đồ tại ghế nha (Case Acceptance Rate)**.- *Đào tạo quy trình Recall dặn dò* ➔ Theo dõi nghiêm ngặt chỉ số **Tỷ lệ lịch nhắc khám thành công (Recall Completion Rate)** hiển thị trên CRM của *Patient OS*.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('94cb2702-86d5-4e6a-93db-250c4c8b9e69','95cce052-512e-4c1d-be4f-031e53bdb857',184,'text','**Mantra tối thượng của Phân hệ Đào tạo:***"Nếu bạn không chịu bỏ chi phí để đào tạo nhân sự, bạn đang chấp nhận trả một mức phí đắt hơn gấp trăm lần cho sự ra đi của khách hàng do những sai lầm cẩu thả của đội ngũ. Đào tạo chính là cách phòng bệnh tốt nhất cho sức khỏe vận hành của một doanh nghiệp nha khoa tử tế."*',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('79fd7cec-3d3d-4ab1-b6e7-a18021548957','19-education-product',NULL,2,'19.9 Trục giao thoa hệ sinh thái:','199-truc-giao-thoa-he-sinh-thai',68,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('6a446231-101d-4f60-ad32-7d3b5bc45b01','79fd7cec-3d3d-4ab1-b6e7-a18021548957',185,'text','**Chiến lược tái cấp năng lực cho Personal Brand, Media Network và Referral System**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('d00e2623-382c-4340-8301-886c69ac3e07','79fd7cec-3d3d-4ab1-b6e7-a18021548957',186,'text','Trong cấu trúc vận hành tổng thể của **Dental Empire OS**, một sai lầm phổ biến của các chủ phòng khám là vận hành phân hệ nội dung, thương hiệu và CSKH thành các phòng ban biệt lập. Phòng Marketing thì vật lộn tìm ý tưởng chạy Ads hằng ngày, Bác sĩ thì chỉ lo điều trị tại ghế, còn bộ phận CSKH thì nhắn tin hỏi thăm một cách sáo rỗng. Sự rời rạc này làm lãng phí nghiêm trọng nguồn lực chất xám của doanh nghiệp.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('8288c36e-8776-47a2-b5ae-2b296f88d0e7','79fd7cec-3d3d-4ab1-b6e7-a18021548957',187,'text','**Education / Product Layer** xuất hiện để giải quyết triệt để bài toán này. Nó đóng vai trò là "nhà máy chế biến trung tâm", thu nhận toàn bộ tinh hoa chuyên môn, ca lâm sàng và tri thức y khoa từ phòng điều trị, đóng gói chúng thành các tài sản hữu hình, sau đó tái cấp năng lượng ngược trở lại để nuôi dưỡng 3 huyết mạch tăng trưởng: **Thương hiệu cá nhân (Personal Brand)**, **Mạng lưới truyền thông (Media Network)**, và **Hệ sinh thái lan tỏa (Referral Ecosystem)**.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('b0774ff6-f664-4e07-8e54-c872d3eb2f11','19-education-product','79fd7cec-3d3d-4ab1-b6e7-a18021548957',3,'Vật chất hóa uy tín: nuôi dưỡng thương hiệu cá chân (Personal Brand)','vat-chat-hoa-uy-tin-nuoi-duong-thuong-hieu-ca-chan-personal-brand',69,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('b1204044-5979-4520-851b-8f2d810dbb8f','b0774ff6-f664-4e07-8e54-c872d3eb2f11',188,'text','Nhiều Bác sĩ hiện nay khi xây dựng Thương hiệu cá nhân (Personal Brand) thường rơi vào cái bẫy "tự nói về mình" (Self-Bragging) liên tục đăng ảnh bằng cấp, chứng chỉ hoặc viết những bài viết mang tính triết lý sáo rỗng. Cách làm này không những không tạo được niềm tin mà còn khiến bộ lọc hoài nghi của khách hàng đề phòng cao hơn.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('a65193cd-b6b8-4939-a964-92df83da42c8','b0774ff6-f664-4e07-8e54-c872d3eb2f11',189,'text','Hệ điều hành **Dental Empire OS** quy định nguyên lý: **"Uy tín không đến từ lời nói, uy tín đến từ tài sản tri thức được vật chất hóa"**.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('fad33195-cbda-48f2-bd00-1cb3f13edbea','b0774ff6-f664-4e07-8e54-c872d3eb2f11',190,'text','Khi phân hệ *Education / Product Layer* được kích hoạt, Bác sĩ/Founder sẽ có một kho chất liệu cao cấp để minh chứng năng lực chuyên môn của mình một cách tự nhiên và nhất quán:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('89e92f6a-3e81-4fc8-ac3c-7dd730ba62fc','b0774ff6-f664-4e07-8e54-c872d3eb2f11',191,'text','- **Từ "Nói mình giỏi" sang "Chứng minh tiêu chuẩn":** Thay vì tuyên bố phòng khám có kỹ thuật Implant hay Răng sứ tốt, Bác sĩ xuất bản một cuốn *Cẩm nang thiết kế nụ cười toàn diện* hoặc bộ *SOP kiểm soát vô trùng phòng nha*. Đây là những bằng chứng thép chứng minh phương pháp và tiêu chuẩn y khoa khắt khe mà phòng khám đang áp dụng.- **Xây dựng vị thế Người dẫn đường (The Authority):** Khi Bác sĩ trực tiếp đứng lớp tại các buổi Workshop cộng đồng, trực tiếp biên soạn tài liệu hướng dẫn hậu phẫu tầng sâu, vị thế của Bác sĩ trong tâm trí bệnh nhân đã dịch chuyển từ một "người thợ sửa răng" trở thành một Chuyên gia/Người dẫn đường đáng tin cậy. Khách hàng sẽ chủ động tìm đến điều trị mà không còn mặc cả về giá.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('10e153e9-5982-43cf-aa7c-02dfe3204ab7','19-education-product','79fd7cec-3d3d-4ab1-b6e7-a18021548957',3,'Kỹ thuật vụn hóa nội dung: động cơ nuôi dưỡng Media Network vô tận','ky-thuat-vun-hoa-noi-dung-ong-co-nuoi-duong-media-network-vo-tan',70,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('5d42687b-6b13-46f1-960d-13d94a8000ee','10e153e9-5982-43cf-aa7c-02dfe3204ab7',192,'text','Nhiều phòng khám RHM luôn rơi vào trạng thái đói nội dung (Content Starvation), nhân sự marketing phải vắt óc suy nghĩ xem hôm nay đăng gì lên Fanpage, ngày mai quay gì trên TikTok. Hệ quả là nội dung làm ra mang tính chắp vá, rời rạc và nghèo nàn giá trị.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('c2a20798-b619-4164-835c-2b9f594840e5','10e153e9-5982-43cf-aa7c-02dfe3204ab7',193,'text','*Education / Product Layer* giải quyết vấn đề này bằng kỹ thuật **Vụn hóa nội dung (Content Atomization Engine)**. Từ một tài sản giáo dục cốt lõi (Core Asset) duy nhất được sản xuất bài bản, hệ thống sẽ tự động bóc tách, nhân bản thành một chuỗi hơn 30 điểm chạm truyền thông đa kênh trên toàn bộ **Media Network**:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('0bca7286-78ea-43f9-ae77-3456af74eaef','10e153e9-5982-43cf-aa7c-02dfe3204ab7',194,'image',NULL,'book/19-education-product/3425393f-83d6-4e56-a173-0efca08fd316-img19.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('00a159a8-ab97-4f8f-87c8-f3a03da08f55','10e153e9-5982-43cf-aa7c-02dfe3204ab7',195,'text','Bằng cách áp dụng mô hình toán học này, phòng khám không bao giờ thiếu nội dung sạch, chất lượng cao. Đội ngũ Marketing của phòng khám chỉ cần tập trung đóng gói thật tốt một tài sản gốc, bộ máy công nghệ phía sau sẽ tự động vận hành dòng thác thông tin phối hợp nhịp nhàng hằng tháng.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('384e2ca3-c39d-4e18-8b3f-6546bf2d1ae6','10e153e9-5982-43cf-aa7c-02dfe3204ab7',196,'text','Lời giới thiệu truyền miệng truyền thống thường có tốc độ lan tỏa rất chậm và dễ bị tam sao thất bản vì nó phụ thuộc hoàn toàn vào trí nhớ và kỹ năng diễn đạt của bệnh nhân cũ. Khi một khách hàng cũ muốn giới thiệu phòng khám của bạn cho người thân đang mất răng, họ chỉ có thể nói chung chung: *"Qua Thích Làm Răng làm đi, bác sĩ ở đó làm tốt và nhẹ nhàng lắm"*. Lời nói này không đủ sức nặng để bẻ gãy nỗi sợ hãi và hoài nghi của người nghe.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('aae0cda8-89eb-4e19-b217-a099a44a87a2','10e153e9-5982-43cf-aa7c-02dfe3204ab7',197,'text','*Education / Product Layer* thay đổi luật chơi bằng chiến lược: **"Số hóa lời giới thiệu thông qua tài sản giáo dục có thể chia sẻ (Shareable Assets)"**.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('4c16c14f-9187-4963-9f4b-c6952b680634','19-education-product','79fd7cec-3d3d-4ab1-b6e7-a18021548957',3,'Referral velocity: khơi thông dòng lan tỏa bằng tài sản có thể chia sẻ','referral-velocity-khoi-thong-dong-lan-toa-bang-tai-san-co-the-chia-se',71,'[]');
