INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('bb7d8d89-08dd-4db1-954a-72b1f757719d','63431707-127b-4f5b-a047-dde3b16c8916',201,'text','Phòng khám gửi tặng bệnh nhân một cuốn *"Cẩm nang bỏ túi: Hướng dẫn chăm sóc và dinh dưỡng khoa học cho người cấy ghép Implant"*. Tài liệu được thiết kế sang trọng, hình ảnh trực quan, đứng tên biên soạn bởi Bác sĩ điều trị chính.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('610d957a-082f-41cc-b7b5-ce730ab5e02a','19-education-product','4c16c14f-9187-4963-9f4b-c6952b680634',4,'Kích hoạt hành vi chia sẻ tự nhiên:','kich-hoat-hanh-vi-chia-se-tu-nhien',74,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('840257f8-b801-4659-8b46-894200f8a263','610d957a-082f-41cc-b7b5-ce730ab5e02a',202,'text','*Điểm chạm 3.*',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('3a430cd7-69c4-4993-a9c1-a924df128f65','610d957a-082f-41cc-b7b5-ce730ab5e02a',203,'text','Khi bệnh nhân về nhà, có người thân hoặc bạn bè cũng đang gặp tình trạng mất răng, rụng răng. Thay vì chỉ nói suông, bệnh nhân cũ chủ động gửi link cẩm nang số hoặc đưa cuốn tài liệu vật lý cho người thân xem: *"Này, đọc cuốn sách hướng dẫn của Bác sĩ Vinh bên Thích Làm Răng viết đi, khoa học và dễ hiểu lắm"*.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('1dfc349d-c5b3-4c0a-a9b2-3ce8785298ae','19-education-product','4c16c14f-9187-4963-9f4b-c6952b680634',4,'Bẻ gãy hoài nghi &amp; Tự động chuyển đổi:','be-gay-hoai-nghi-amp-tu-ong-chuyen-oi',75,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('e6b7d460-0cc0-4d8a-8a1b-6c44bdea128c','1dfc349d-c5b3-4c0a-a9b2-3ce8785298ae',204,'text','*Điểm chạm 4.*',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('b73cabc1-069b-4f4f-9e8a-b734f1a75de0','1dfc349d-c5b3-4c0a-a9b2-3ce8785298ae',205,'text','Người thân đọc tài liệu, tiếp nhận tri thức y khoa thường thức, tự động bị thuyết phục bởi năng lực chuyên gia của Bác sĩ. Họ quét mã QR đính kèm cuối trang sách để tự động đặt lịch hẹn tư vấn tại ghế nha.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('b319106e-2871-4c66-af5b-58fb7359b47d','1dfc349d-c5b3-4c0a-a9b2-3ce8785298ae',206,'text','**Mantra vận hành trục liên kết:**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('0c3e9220-010b-4a3a-beac-58310d77ded7','1dfc349d-c5b3-4c0a-a9b2-3ce8785298ae',207,'text','*"Referral đỉnh cao không đến từ việc van nài khách hàng đi giới thiệu hộ, mà đến từ việc cung cấp cho họ những tài sản tri thức đủ giá trị để họ tự hào mang đi chia sẻ với thế giới xung quanh."*',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('ddd71be8-824f-4e60-84e8-7f36abce8f75','1dfc349d-c5b3-4c0a-a9b2-3ce8785298ae',208,'text','Khi trục liên kết này được vận hành trơn tru, **Education / Product Layer** chính là trái tim bơm máu liên tục cho bộ máy thương hiệu, giữ cho dòng chảy Lead mới đổ về phòng khám luôn đạt trạng thái dồi dào, hữu cơ và bền vững tuyệt đối trước mọi biến động thị trường.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('2b79004e-4217-40f6-a005-3a4ce4404b66','19-education-product',NULL,2,'19.10 Kết luận chương 15: Bản chất của cỗ máy tăng trưởng vĩnh cửu hệ sinh thái','1910-ket-luan-chuong-15-ban-chat-cua-co-may-tang-truong-vinh-cuu-he-sinh-thai',76,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('669f65a2-ac6e-4a8f-b553-3ad89f652412','2b79004e-4217-40f6-a005-3a4ce4404b66',209,'text','Bước đi tối thượng phân tách một nha khoa kỹ trị thông thường với một đế chế nha khoa vận hành theo tiêu chuẩn **Dental Empire OS** nằm ở tư duy sở hữu tài sản. Khi phòng khám của bạn chỉ dừng lại ở việc điều trị, bạn đang bán thời gian và sức lao động lâm sàng đơn thuần. Nhưng khi bạn kích hoạt **Education / Product Layer**, bạn chính thức bước vào nền kinh tế tri thức nơi chuyên môn y khoa được vật chất hóa thành các tài sản có khả năng nhân bản, mở rộng và tự động phân phối không giới hạn.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('a69f5204-b196-492b-ab80-72aedf138179','2b79004e-4217-40f6-a005-3a4ce4404b66',210,'text','Tầng chiến lược này tháo gỡ hoàn toàn bài toán chi phí marketing (CAC) ngày một leo thang bằng cách xây dựng một bộ lọc thông tin sạch. Thay vì liên tục ném tiền vào các chiến dịch quảng cáo chèo kéo, phòng khám lấy giáo dục làm gốc để nuôi dưỡng lòng trung thành, biến khách hàng từ những người xa lạ thành những thành viên thuộc về một bộ tộc nụ cười gắn kết.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('c898368c-ae9b-46fe-b301-ad8339dfd1b0','2b79004e-4217-40f6-a005-3a4ce4404b66',211,'image',NULL,'book/19-education-product/5f820ece-303c-4ece-8ed7-4664134f925f-img20.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('4f491082-5028-48e4-a81d-6e80ccbc3bb3','2b79004e-4217-40f6-a005-3a4ce4404b66',212,'text','Để kết lại toàn bộ kiến trúc vận hành của Chương 15, đây là kim chỉ nam cốt lõi mà Nhà quản trị và toàn bộ đội ngũ vận hành hệ thống bắt buộc phải thuộc nằm lòng:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('7291d3f6-fd78-4ef2-875e-b8ae34d10651','2b79004e-4217-40f6-a005-3a4ce4404b66',213,'text','**Education / Product Layer là tầng chiến lược biến chuyên môn nha khoa thuần túy thành các tài sản giáo dục, giải pháp sản phẩm, kiến trúc cộng đồng và tạo ra dòng tăng trưởng hữu cơ quay ngược lại nuôi dưỡng, bảo vệ sức khỏe thương hiệu trọn đời.**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('2d3bbded-079b-4243-b68a-6d6979c8dd34','2b79004e-4217-40f6-a005-3a4ce4404b66',214,'text','Khi pháo đài tri thức này được thiết lập hoàn chỉnh, nha khoa của bạn sẽ chính thức thoát khỏi vòng xoáy nghiện quảng cáo trả phí, tự tin vận hành một bộ máy kinh doanh thịnh vượng, tử tế, mang lại giá trị thực chứng cho cộng đồng và phát triển bền vững trước mọi sóng gió của thị trường',NULL,NULL,NULL,NULL,NULL);
